function subsets(nums) {
  const result = [];

  function backtrack(index, current) {
    if (index === nums.length) {
      result.push([...current]);
      return;
    }

    backtrack(index + 1, current);

    current.push(nums[index]);
    backtrack(index + 1, current);
    current.pop();
  }

