    components = n
    for u, v in edges:
        components -= union(u, v)
    return components
```

Example:
```python
print(count_components(5, [[0, 1], [1, 2], [3, 4]]))  # 2
```

This starts with `n` separate components and decreases the count whenever a union merges two different sets.

280.answer:
```python
def minimum_spanning_tree_weight(n, edges):
    parent = list(range(n + 1))
    rank = [0] * (n + 1)

    def find(x):
        if parent[x] != x:
            parent[x] = find(parent[x])
        return parent[x]

    def union(a, b):
        ra, rb = find(a), find(b)
        if ra == rb:
            return False
        if rank[ra] < rank[rb]:
            parent[ra] = rb
        elif rank[ra] > rank[rb]:
            parent[rb] = ra
        else:
            parent[rb] = ra
            rank[ra] += 1
        return True

    total = 0
    used = 0

    for u, v, w in sorted(edges, key=lambda e: e[2]):
        if union(u, v):
            total += w
            used += 1
            if used == n - 1:
                return total

    return -1
```

Uses Kruskal’s algorithm: sort edges by weight, add an edge if it connects two different components, and return `-1` if fewer than `n - 1` edges can be chosen.

