```js
function isPlainObject(value) {
  return value !== null && typeof value === 'object' && !Array.isArray(value);
}

function deepMerge(a, b) {
  if (!isPlainObject(a) || !isPlainObject(b)) {
    throw new TypeError('deepMerge expects two plain objects');
  }

  const result = {};
  const keys = new Set([...Object.keys(a), ...Object.keys(b)]);

  for (const key of keys) {
    const aHasKey = Object.prototype.hasOwnProperty.call(a, key);
    const bHasKey = Object.prototype.hasOwnProperty.call(b, key);

    if (!bHasKey) {
      result[key] = isPlainObject(a[key])
        ? deepMerge({}, a[key])
        : Array.isArray(a[key])
          ? a[key].slice()
          : a[key];
      continue;
    }

    if (!aHasKey) {
      result[key] = isPlainObject(b[key])
        ? deepMerge({}, b[key])
        : Array.isArray(b[key])
          ? b[key].slice()
          : b[key];
      continue;
    }

    if (isPlainObject(a[key]) && isPlainObject(b[key])) {
      result[key] = deepMerge(a[key], b[key]);
      continue;
    }

    if (Array.isArray(b[key])) {
      result[key] = b[key].slice();
      continue;
    }

    if (isPlainObject(b[key])) {
      result[key] = deepMerge({}, b[key]);
      continue;
    }

    result[key] = b[key];
  }

  return result;
}

module.exports = { deepMerge };
```

