  assert.deepStrictEqual(
    deepMerge({ a: 1 }, { a: 2 }),
    { a: 2 }
  );

  // 3. merges nested objects recursively
  assert.deepStrictEqual(
    deepMerge({ a: { x: 1 } }, { a: { y: 2 } }),
    { a: { x: 1, y: 2 } }
  );

  // 4. arrays are overwritten, not merged
  assert.deepStrictEqual(
    deepMerge({ a: [1, 2] }, { a: [3] }),
    { a: [3] }
  );

  // 5. null overwrites existing object
  assert.deepStrictEqual(
    deepMerge({ a: { x: 1 } }, { a: null }),
    { a: null }
  );

  // 6. missing keys from b are preserved
  assert.deepStrictEqual(
    deepMerge({ a: 1, b: 2 }, { b: 3 }),
    { a: 1, b: 3 }
  );

  // 7. conflicting primitive and object types prefer b
  assert.deepStrictEqual(
    deepMerge({ a: 1 }, { a: { nested: true } }),
    { a: { nested: true } }
  );

  // 8. empty objects merge correctly
  assert.deepStrictEqual(
    deepMerge({}, {}),
    {}
  );

  // 9. deep nesting works
  assert.deepStrictEqual(
    deepMerge(
      { a: { b: { c: { d: 1 } } } },
      { a: { b: { c: { e: 2 } } } }
    ),
    { a: { b: { c: { d: 1, e: 2 } } } }
  );

  // 10. does not mutate inputs
  const left = { a: { x: 1 }, arr: [1, 2] };
  const right = { a: { y: 2 }, arr: [3] };
  const leftBefore = JSON.parse(JSON.stringify(left));
  const rightBefore = JSON.parse(JSON.stringify(right));
  const merged = deepMerge(left, right);

