  assert.deepStrictEqual(right, rightBefore);
  assert.notStrictEqual(merged.a, left.a);
  assert.notStrictEqual(merged.arr, right.arr);

  // 11. nested missing keys are preserved and added
  assert.deepStrictEqual(
    deepMerge(
      { config: { retries: 3, cache: true } },
      { config: { cache: false, timeout: 1000 } }
    ),
    { config: { retries: 3, cache: false, timeout: 1000 } }
  );

  // 12. throws for non-object inputs
  assert.throws(() => deepMerge(null, {}), TypeError);
