```js
function normalizePhoneNumber(input, defaultCountry = 'US') {
  if (input == null) {
    return null;
  }

  const raw = String(input).trim();
  if (!raw) {
    return null;
  }

  const country = String(defaultCountry || '').toUpperCase();
  const countryRules = {
    US: { countryCode: '1', nationalLength: 10 },
    CA: { countryCode: '1', nationalLength: 10 },
    GB: { countryCode: '44', nationalLength: [10, 11] },
    FR: { countryCode: '33', nationalLength: 9 },
  };

  const rule = countryRules[country];
  if (!rule) {
    throw new Error(`Unsupported defaultCountry: ${defaultCountry}`);
  }

  const extMatch = raw.match(/(?:ext\.?|extension|x)\s*(\d+)$/i);
  const extension = extMatch ? extMatch[1] : null;
  const withoutExtension = extMatch ? raw.slice(0, extMatch.index).trim() : raw;

  if (/[A-WY-Za-wy-z]/.test(withoutExtension)) {
    throw new Error('Phone number contains invalid characters');
  }

  let normalizedInput = withoutExtension.replace(/\s+/g, '');
  normalizedInput = normalizedInput.replace(/^00/, '+');

  if (/[^\d()+\-.]/.test(normalizedInput)) {
    throw new Error('Phone number contains invalid characters');
  }

  let digits = normalizedInput.replace(/\D/g, '');

  if (!digits) {
    return null;
  }

  if (normalizedInput.startsWith('+')) {
    // already international
  } else if (digits.startsWith(rule.countryCode) && String(rule.nationalLength).includes(String(digits.length - rule.countryCode.length))) {
    normalizedInput = `+${digits}`;
  } else {
    if (country === 'US' || country === 'CA') {
      if (digits.length === 11 && digits.startsWith('1')) {
        digits = digits.slice(1);
      }
      if (digits.length !== 10) {
        throw new Error('Invalid national phone number length');
      }
      normalizedInput = `+1${digits}`;
    } else if (country === 'FR') {
      if (digits.startsWith('0')) {
        digits = digits.slice(1);
      }
      if (digits.length !== 9) {
        throw new Error('Invalid national phone number length');
      }
      normalizedInput = `+33${digits}`;
    } else if (country === 'GB') {
      if (digits.startsWith('0')) {
        digits = digits.slice(1);
      }
      if (![9, 10].includes(digits.length)) {
        throw new Error('Invalid national phone number length');
      }
      normalizedInput = `+44${digits}`;
    }
  }

  const e164 = `+${normalizedInput.replace(/\D/g, '').replace(/^+/, '')}`;
  return extension ? `${e164}x${extension}` : e164;
}

// Tests
const cases = [
  { input: '  (415) 555-2671  ', country: 'US', expected: '+14155552671' },
  { input: '415.555.2671', country: 'US', expected: '+14155552671' },
  { input: '+1 415 555 2671', country: 'US', expected: '+14155552671' },
  { input: '001 415 555 2671', country: 'US', expected: '+14155552671' },
  { input: '+33 6 12 34 56 78', country: 'FR', expected: '+33612345678' },
  { input: '06 12 34 56 78 ext 99', country: 'FR', expected: '+33612345678x99' },
  { input: '', country: 'US', expected: null },
  { input: null, country: 'US', expected: null },
  { input: '+14155552671', country: 'US', expected: '+14155552671' },
];

for (const test of cases) {
  const actual = normalizePhoneNumber(test.input, test.country);
  console.assert(
    actual === test.expected,
    `Expected ${JSON.stringify(test.expected)}, got ${JSON.stringify(actual)} for ${JSON.stringify(test.input)}`
  );
}

const errorCases = [
  { input: '415-555-CODE', country: 'US' },
  { input: '12345', country: 'US' },
];

for (const test of errorCases) {
  let threw = false;
  try {
    normalizePhoneNumber(test.input, test.country);
  } catch {
    threw = true;
  }
  console.assert(threw, `Expected error for ${JSON.stringify(test.input)}`);
}
```

Assumptions:
- Normalized format is E.164-like: `+<countrycode><nationalnumber>` with optional `x<extension>`.
- Empty or nullish input returns `null`.
- Letters in the main number are rejected rather than mapped from vanity numbers.
- Only `US`, `CA`, `GB`, and `FR` are supported here for national-format parsing.
- International numbers already starting with `+` are preserved as digits-only normalized output.
- `00` is treated as an international prefix and converted to `+`.
- Extensions are recognized only at the end via `ext`, `extension`, or `x` followed by digits.

