```js
function flattenObject(obj) {
  if (obj === null || typeof obj !== 'object' || Array.isArray(obj)) {
    return {};
  }

  const result = {};

  function visit(value, path) {
    if (Array.isArray(value)) {
      if (path) result[path] = value;
      return;
    }

    if (value === null || typeof value !== 'object') {
      if (path) result[path] = value;
      return;
    }

    const entries = Object.entries(value);
    if (entries.length === 0) {
      if (path) result[path] = {};
      return;
    }

    for (const [key, nestedValue] of entries) {
      const nextPath = path ? `${path}.${key}` : key;
      visit(nestedValue, nextPath);
    }
  }

  visit(obj, '');
  return result;
}
```

**Array representation:** arrays are treated as leaf values and kept intact at their flattened key. This avoids ambiguity between real object keys and numeric indexes.

