```js
function binarySearchRange(nums, target) {
  function findBoundary(isFirst) {
    let left = 0;
    let right = nums.length - 1;
    let boundary = -1;

    while (left <= right) {
      const mid = left + Math.floor((right - left) / 2);

      if (nums[mid] === target) {
        boundary = mid;
        if (isFirst) {
          right = mid - 1;
        } else {
          left = mid + 1;
        }
      } else if (nums[mid] < target) {
        left = mid + 1;
      } else {
        right = mid - 1;
      }
    }

    return boundary;
  }

  return [findBoundary(true), findBoundary(false)];
}

// Tests
function runTests() {
  const tests = [
    {
      name: 'target appears in middle duplicates',
      nums: [1, 2, 2, 2, 3, 4],
      target: 2,
      expected: [1, 3],
    },
    {
      name: 'target missing',
      nums: [1, 2, 3, 4, 5],
      target: 6,
      expected: [-1, -1],
    },
    {
      name: 'all values equal to target',
      nums: [7, 7, 7, 7],
      target: 7,
      expected: [0, 3],
    },
    {
      name: 'empty array',
      nums: [],
      target: 3,
      expected: [-1, -1],
    },
    {
      name: 'single-element array hit',
      nums: [5],
      target: 5,
      expected: [0, 0],
    },
    {
      name: 'single-element array miss',
      nums: [5],
      target: 2,
      expected: [-1, -1],
    },
    {
      name: 'duplicates at both ends of matching block',
      nums: [1, 1, 2, 3, 4, 4],
      target: 1,
      expected: [0, 1],
    },
    {
      name: 'duplicates at array end',
      nums: [1, 2, 3, 4, 4, 4],
      target: 4,
      expected: [3, 5],
    },
    {
      name: 'negative numbers',
      nums: [-10, -5, -5, -2, 0, 3],
      target: -5,
      expected: [1, 2],
    },
    {
      name: 'large sorted input',
      nums: Array.from({ length: 100000 }, (_, i) => Math.floor(i / 3)),
      target: 12345,
      expected: [12345 * 3, 12345 * 3 + 2],
    },
  ];

  for (const { name, nums, target, expected } of tests) {
    const actual = binarySearchRange(nums, target);
    const pass = actual[0] === expected[0] && actual[1] === expected[1];
    console.assert(
      pass,
      `${name} failed: expected [${expected}], got [${actual}]`
    );
  }

  console.log(`Passed ${tests.length} tests`);
}

runTests();
```

This uses two binary searches, so it stays `O(log n)` time and `O(1)` extra space.

