  { added: [4], removed: [1], unchanged: [2, 3] }
);

assert.deepStrictEqual(
  diffArrays([], []),
  { added: [], removed: [], unchanged: [] }
);

assert.deepStrictEqual(
  diffArrays([], [1, 2]),
  { added: [1, 2], removed: [], unchanged: [] }
);

assert.deepStrictEqual(
