  { added: [2], removed: [1], unchanged: [1, 2] }
);

assert.deepStrictEqual(
  diffArrays([1, '1', true, false], ['1', 1, false, null]),
  { added: [null], removed: [true], unchanged: [1, '1', false] }
);

assert.deepStrictEqual(
  diffArrays([1, 2, 3], [3, 2, 1]),
  { added: [], removed: [], unchanged: [1, 2, 3] }
);

assert.deepStrictEqual(
  diffArrays([null, undefined, 0], [undefined, null, 0, undefined]),
  { added: [undefined], removed: [], unchanged: [null, undefined, 0] }
);

assert.deepStrictEqual(
  diffArrays(['a', 'b'], ['a', 'b']),
  { added: [], removed: [], unchanged: ['a', 'b'] }
);

assert.throws(() => diffArrays(null, []), /expects two arrays/);
assert.throws(() => diffArrays([], undefined), /expects two arrays/);

console.log('All tests passed');
