function slugify(input) {
  const charMap = {
    ß: 'ss', Æ: 'ae', æ: 'ae', Ø: 'o', ø: 'o', Å: 'a', å: 'a',
    Þ: 'th', þ: 'th', Đ: 'd', đ: 'd', Ł: 'l', ł: 'l', Œ: 'oe', œ: 'oe'
  };

  const cyrillicMap = {
    А: 'a', Б: 'b', В: 'v', Г: 'g', Д: 'd', Е: 'e', Ё: 'e', Ж: 'zh', З: 'z', И: 'i', Й: 'i',
    К: 'k', Л: 'l', М: 'm', Н: 'n', О: 'o', П: 'p', Р: 'r', С: 's', Т: 't', У: 'u', Ф: 'f',
    Х: 'kh', Ц: 'ts', Ч: 'ch', Ш: 'sh', Щ: 'shch', Ы: 'y', Э: 'e', Ю: 'yu', Я: 'ya', Ъ: '', Ь: '',
    а: 'a', б: 'b', в: 'v', г: 'g', д: 'd', е: 'e', ё: 'e', ж: 'zh', з: 'z', и: 'i', й: 'i',
    к: 'k', л: 'l', м: 'm', н: 'n', о: 'o', п: 'p', р: 'r', с: 's', т: 't', у: 'u', ф: 'f',
    х: 'kh', ц: 'ts', ч: 'ch', ш: 'sh', щ: 'shch', ы: 'y', э: 'e', ю: 'yu', я: 'ya', ъ: '', ь: ''
  };

  const transliterateChar = (char) => {
    if (charMap[char]) return charMap[char];
    if (cyrillicMap[char]) return cyrillicMap[char];
    return char;
  };

  return String(input ?? '')
    .trim()
    .split('')
    .map(transliterateChar)
    .join('')
    .normalize('NFKD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/['’]/g, '')
    .replace(/&/g, ' and ')
    .replace(/[^a-z0-9\s-]/g, ' ')
    .replace(/[-\s]+/g, '-')
    .replace(/^-+|-+$/g, '');
}

module.exports = { slugify };
