```js
function compareVersions(a, b) {
  const parse = (input) => {
    if (typeof input !== "string") return { valid: false, reason: "not a string" };

    const value = input.trim();
    if (!value) return { valid: false, reason: "empty string" };

    const match = value.match(
      /^(\d+)(?:\.(\d+))?(?:\.(\d+))?(?:-([0-9A-Za-z-]+(?:\.[0-9A-Za-z-]+)*))?$/
    );

    if (!match) return { valid: false, reason: "invalid format" };

    const [, major = "0", minor = "0", patch = "0", prerelease] = match;

    const core = [major, minor, patch].map((part) => {
      const normalized = part.replace(/^0+(?=\d)/, "");
      return normalized === "" ? 0 : Number(normalized);
    });

    const prereleaseParts = prerelease
      ? prerelease.split(".").map((part) => {
          if (/^\d+$/.test(part)) {
            return {
              type: "number",
              value: Number(part.replace(/^0+(?=\d)/, "") || "0"),
              raw: part,
            };
          }
          return { type: "string", value: part };
        })
      : null;

    return { valid: true, core, prereleaseParts };
  };

  const pa = parse(a);
  const pb = parse(b);

  if (!pa.valid && !pb.valid) return 0;
  if (!pa.valid) return -1;
  if (!pb.valid) return 1;

  for (let i = 0; i < 3; i++) {
    if (pa.core[i] < pb.core[i]) return -1;
    if (pa.core[i] > pb.core[i]) return 1;
  }

  const aPre = pa.prereleaseParts;
  const bPre = pb.prereleaseParts;

  if (!aPre && !bPre) return 0;
  if (!aPre) return 1;
  if (!bPre) return -1;

  const len = Math.max(aPre.length, bPre.length);

  for (let i = 0; i < len; i++) {
    const x = aPre[i];
    const y = bPre[i];

    if (!x) return -1;
    if (!y) return 1;

    if (x.type === "number" && y.type === "number") {
      if (x.value < y.value) return -1;
      if (x.value > y.value) return 1;
      continue;
    }

    if (x.type === "number" && y.type === "string") return -1;
    if (x.type === "string" && y.type === "number") return 1;

    if (x.value < y.value) return -1;
    if (x.value > y.value) return 1;
  }

  return 0;
}
