function humanFileSize(bytes) {
  if (typeof bytes !== 'number' || Number.isNaN(bytes) || !Number.isFinite(bytes)) {
    throw new TypeError('bytes must be a finite number');
  }

  const base = 1024;
  const units = ['B', 'KB', 'MB', 'GB', 'TB', 'PB', 'EB'];
  const sign = bytes < 0 ? '-' : '';
  let value = Math.abs(bytes);

  if (value < 1) {
    return `${sign}${value % 1 === 0 ? value.toFixed(0) : value} B`;
  }

  let unitIndex = 0;
  while (value >= base && unitIndex < units.length - 1) {
    value /= base;
    unitIndex++;
  }

  const rounded = value >= 10 || value % 1 === 0
    ? value.toFixed(0)
    : value.toFixed(1);

  return `${sign}${rounded} ${units[unitIndex]}`;
}

module.exports = { humanFileSize };
```

Uses **base-1024** units: `1 KB = 1024 B`.

