function intersectIntervals(intervals) {
  if (!Array.isArray(intervals)) {
    throw new TypeError('intervals must be an array');
  }

  if (intervals.length === 0) {
    return null;
  }

  let maxStart = -Infinity;
  let minEnd = Infinity;

  for (const interval of intervals) {
    if (!Array.isArray(interval) || interval.length !== 2) {
      throw new TypeError('each interval must be a [start, end] pair');
    }

    let [start, end] = interval;

    if (typeof start !== 'number' || typeof end !== 'number' || Number.isNaN(start) || Number.isNaN(end)) {
      throw new TypeError('interval endpoints must be valid numbers');
    }

    if (start > end) {
      [start, end] = [end, start];
    }

    if (start > maxStart) maxStart = start;
    if (end < minEnd) minEnd = end;
  }

  return maxStart <= minEnd ? [maxStart, minEnd] : null;
}

module.exports = { intersectIntervals };
