```js
function wordWrap(text, maxWidth) {
  if (!Number.isInteger(maxWidth) || maxWidth < 1) {
    throw new TypeError('maxWidth must be a positive integer');
  }
  if (typeof text !== 'string') {
    throw new TypeError('text must be a string');
  }
  if (text === '') {
    return '';
  }

  const lines = text.split('\n');
  const wrapped = lines.map(wrapLine);
  return wrapped.join('\n');

  function wrapLine(line) {
    if (line === '') {
      return '';
    }

    const tokens = line.match(/\S+|\s+/g) || [];
    const out = [];
    let current = '';

    for (const token of tokens) {
      if (/^\s+$/.test(token)) {
        if (current !== '') {
          current += token;
        }
        continue;
      }

      if (current === '') {
        if (token.length <= maxWidth) {
          current = token;
        } else {
          pushChunks(token, out);
        }
        continue;
      }

      if (current.length + token.length <= maxWidth) {
        current += token;
        continue;
      }

      out.push(current.replace(/[ \t]+$/g, ''));
      current = '';

      if (token.length <= maxWidth) {
        current = token;
      } else {
        pushChunks(token, out);
      }
    }

    if (current !== '') {
      out.push(current.replace(/[ \t]+$/g, ''));
    }

    return out.join('\n');
  }

  function pushChunks(word, out) {
    for (let i = 0; i < word.length; i += maxWidth) {
      out.push(word.slice(i, i + maxWidth));
    }
  }
}

module.exports = { wordWrap };
```

