```js
function buildTree(items) {
  if (!Array.isArray(items)) {
    throw new TypeError('items must be an array');
  }

  const nodes = new Map();
  const parentById = new Map();

  for (let i = 0; i < items.length; i++) {
    const item = items[i];

    if (!item || typeof item !== 'object' || Array.isArray(item)) {
      throw new TypeError(`items[${i}] must be an object`);
    }

    const { id, parentId } = item;

    if (id === undefined || id === null) {
      throw new TypeError(`items[${i}].id is required`);
    }

    if (nodes.has(id)) {
      throw new Error(`Duplicate id: ${String(id)}`);
    }

    nodes.set(id, { ...item, children: [] });
    parentById.set(id, parentId ?? null);
  }

  const roots = [];

  for (const [id, node] of nodes) {
    const parentId = parentById.get(id);

    if (parentId == null) {
      roots.push(node);
      continue;
    }

    const parent = nodes.get(parentId);
    if (!parent) {
      throw new Error(`Missing parent: ${String(parentId)} for node ${String(id)}`);
    }

    parent.children.push(node);
  }

  const visiting = new Set();
  const visited = new Set();

  function visit(node) {
    if (visited.has(node.id)) return;
    if (visiting.has(node.id)) {
      throw new Error(`Cycle detected at id: ${String(node.id)}`);
    }

    visiting.add(node.id);
    for (const child of node.children) {
      visit(child);
    }
    visiting.delete(node.id);
    visited.add(node.id);
  }

  for (const node of roots) {
    visit(node);
  }

  if (visited.size !== nodes.size) {
    const unvisitedId = [...nodes.keys()].find((id) => !visited.has(id));
    throw new Error(`Cycle detected involving id: ${String(unvisitedId)}`);
  }

  return roots;
}
