  }

  const visiting = new Set();
  const visited = new Set();

  function visit(node) {
    if (visited.has(node.id)) return;
    if (visiting.has(node.id)) {
      throw new Error(`Cycle detected at id: ${String(node.id)}`);
    }

    visiting.add(node.id);
    for (const child of node.children) {
      visit(child);
    }
    visiting.delete(node.id);
    visited.add(node.id);
  }

  for (const node of roots) {
    visit(node);
  }

  if (visited.size !== nodes.size) {
    const unvisitedId = [...nodes.keys()].find((id) => !visited.has(id));
    throw new Error(`Cycle detected involving id: ${String(unvisitedId)}`);
  }

  return roots;
}

