function relativePath(from, to) {
  if (typeof from !== 'string' || typeof to !== 'string') {
    throw new TypeError('Both paths must be strings');
  }

  const normalize = (input) => {
    if (!input) throw new TypeError('Paths must be non-empty absolute strings');

    const unified = input.replace(/\\/g, '/');
    const isAbsolute = unified.startsWith('/');
    if (!isAbsolute) {
      throw new TypeError(`Path must be absolute: ${input}`);
    }

    const parts = unified
      .split('/')
      .filter(Boolean);

    return parts;
  };

  const fromParts = normalize(from);
  const toParts = normalize(to);

  let i = 0;
  while (
    i < fromParts.length &&
    i < toParts.length &&
    fromParts[i] === toParts[i]
  ) {
    i++;
  }

  const up = new Array(fromParts.length - i).fill('..');
  const down = toParts.slice(i);
  const result = [...up, ...down].join('/');

  return result || '.';
}

module.exports = { relativePath };
```

