```js
/**
 * Sort an array of objects by multiple rules.
 *
 * Assumptions:
 * - Each rule is an object: { key: string, direction?: 'asc' | 'desc' }.
 * - Missing/null/undefined values sort after present values in ascending order
 *   and before present values in descending order.
 * - Numbers compare numerically.
 * - Strings compare with localeCompare using numeric ordering.
 * - Booleans compare false < true.
 * - Dates compare by timestamp.
 * - Other mixed types fall back to type-name comparison, then string coercion.
 * - The sort is stable: if all rule comparisons are equal, original input order is preserved.
 * - The input array is not mutated.
 */
function sortByMultiple(items, rules) {
  if (!Array.isArray(items)) {
    throw new TypeError('items must be an array');
  }
  if (!Array.isArray(rules)) {
    throw new TypeError('rules must be an array');
  }
  if (items.length <= 1 || rules.length === 0) {
    return items.slice();
  }

  const directionMultiplier = (direction) => {
    if (direction == null || direction === 'asc') return 1;
    if (direction === 'desc') return -1;
    throw new TypeError(`Invalid sort direction: ${direction}`);
  };

  const typeRank = (value) => {
    if (value == null) return 6;
    if (typeof value === 'number') return 0;
    if (typeof value === 'string') return 1;
    if (typeof value === 'boolean') return 2;
    if (value instanceof Date) return 3;
    if (typeof value === 'bigint') return 4;
    return 5;
  };

  const compareValues = (a, b) => {
    const aMissing = a == null;
    const bMissing = b == null;

    if (aMissing && bMissing) return 0;
    if (aMissing) return 1;
    if (bMissing) return -1;

    const aRank = typeRank(a);
    const bRank = typeRank(b);

    if (aRank !== bRank) return aRank - bRank;

    if (typeof a === 'number' && typeof b === 'number') {
      return a - b;
    }

    if (typeof a === 'string' && typeof b === 'string') {
      return a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' });
    }

    if (typeof a === 'boolean' && typeof b === 'boolean') {
      return Number(a) - Number(b);
    }

    if (a instanceof Date && b instanceof Date) {
      return a.getTime() - b.getTime();
    }

    if (typeof a === 'bigint' && typeof b === 'bigint') {
      return a < b ? -1 : a > b ? 1 : 0;
    }

    const typeNameA = Object.prototype.toString.call(a);
    const typeNameB = Object.prototype.toString.call(b);
    if (typeNameA !== typeNameB) {
      return typeNameA.localeCompare(typeNameB);
    }

    return String(a).localeCompare(String(b), undefined, { numeric: true, sensitivity: 'base' });
  };

  return items
    .map((item, index) => ({ item, index }))
    .sort((left, right) => {
      for (const rule of rules) {
        if (!rule || typeof rule.key !== 'string' || rule.key.length === 0) {
          throw new TypeError('Each rule must have a non-empty string key');
        }

        const multiplier = directionMultiplier(rule.direction);
        const comparison = compareValues(left.item[rule.key], right.item[rule.key]);
        if (comparison !== 0) {
          return comparison * multiplier;
        }
      }

      return left.index - right.index;
    })
    .map(({ item }) => item);
}

module.exports = { sortByMultiple };
```

