function parseBoolean(input) {
  if (typeof input === 'boolean') return input;

  if (typeof input === 'number') {
    if (input === 1) return true;
    if (input === 0) return false;
    throw new TypeError(`Invalid boolean number: ${input}`);
  }

  if (typeof input === 'string') {
    const normalized = input.trim().toLowerCase();

    if (normalized === 'true' || normalized === '1' || normalized === 'yes') {
      return true;
    }

    if (normalized === 'false' || normalized === '0' || normalized === 'no') {
      return false;
    }

    if (normalized === '') {
      throw new TypeError('Empty string is not a valid boolean value');
    }

    throw new TypeError(`Invalid boolean string: ${input}`);
  }

  if (input == null) {
    throw new TypeError('Nullish value is not a valid boolean input');
  }

  throw new TypeError(`Unsupported input type: ${typeof input}`);
}

module.exports = { parseBoolean };
```

