```js
function minWindowSubstring(text, pattern) {
  if (pattern.length === 0) return "";
  if (text.length === 0 || pattern.length > text.length) return "";

  const need = new Map();
  for (const ch of pattern) {
    need.set(ch, (need.get(ch) || 0) + 1);
  }

  let missing = pattern.length;
  let left = 0;
  let bestStart = 0;
  let bestLen = Infinity;

  for (let right = 0; right < text.length; right++) {
    const ch = text[right];
    if (need.has(ch)) {
      const count = need.get(ch);
      if (count > 0) missing--;
      need.set(ch, count - 1);
    }

    while (missing === 0) {
      const windowLen = right - left + 1;
      if (windowLen < bestLen) {
        bestLen = windowLen;
        bestStart = left;
      }

      const leftChar = text[left];
      if (need.has(leftChar)) {
        const count = need.get(leftChar) + 1;
        need.set(leftChar, count);
        if (count > 0) missing++;
      }
      left++;
    }
  }

  return bestLen === Infinity ? "" : text.slice(bestStart, bestStart + bestLen);
}
