function nearestPalindrome(n) {
  if (typeof n !== 'string' || !/^[0-9]+$/.test(n) || n.length === 0) {
    throw new TypeError('n must be a non-empty string of digits');
  }

  const normalize = (s) => {
    const stripped = s.replace(/^0+(?!$)/, '');
    return stripped;
  };

  const compareNumStr = (a, b) => {
    a = normalize(a);
    b = normalize(b);
    if (a.length !== b.length) return a.length - b.length;
    if (a === b) return 0;
    return a < b ? -1 : 1;
  };

  const absDiff = (a, b) => {
    a = normalize(a);
    b = normalize(b);
    if (compareNumStr(a, b) < 0) [a, b] = [b, a];

    let i = a.length - 1;
    let j = b.length - 1;
    let borrow = 0;
    let out = '';

    while (i >= 0 || j >= 0) {
      let da = i >= 0 ? a.charCodeAt(i) - 48 : 0;
      const db = j >= 0 ? b.charCodeAt(j) - 48 : 0;
      da -= borrow;
      if (da < db) {
        da += 10;
        borrow = 1;
      } else {
        borrow = 0;
      }
      out = String(da - db) + out;
      i--;
      j--;
    }

    return normalize(out);
  };

  const addOne = (s) => {
    const arr = s.split('');
    let carry = 1;
    for (let i = arr.length - 1; i >= 0 && carry; i--) {
      const digit = arr[i].charCodeAt(0) - 48 + carry;
      arr[i] = String(digit % 10);
      carry = digit > 9 ? 1 : 0;
    }
    if (carry) arr.unshift('1');
    return arr.join('');
  };

  const subOne = (s) => {
    if (normalize(s) === '0') return '0';
    const arr = s.split('');
    let i = arr.length - 1;
    while (i >= 0 && arr[i] === '0') {
      arr[i] = '9';
      i--;
    }
    arr[i] = String((arr[i].charCodeAt(0) - 48) - 1);
    return normalize(arr.join(''));
  };

  const makePalindrome = (left, odd) => {
    const rev = left.split('').reverse().join('');
    return odd ? left + rev.slice(1) : left + rev;
  };

  const len = n.length;
  const odd = len % 2 === 1;
  const leftLen = Math.ceil(len / 2);
  const prefix = n.slice(0, leftLen);

  const candidates = new Set();
  candidates.add(makePalindrome(prefix, odd));
  candidates.add(makePalindrome(addOne(prefix), odd));
  candidates.add(makePalindrome(subOne(prefix), odd));
  candidates.add('9'.repeat(len - 1) || '0');
  candidates.add('1' + '0'.repeat(len - 1) + '1');

  let best = null;
  let bestDiff = null;

  for (const candidate of candidates) {
    const cand = normalize(candidate);
    if (cand === normalize(n)) continue;
    const diff = absDiff(cand, n);
    if (
      best === null ||
      compareNumStr(diff, bestDiff) < 0 ||
      (compareNumStr(diff, bestDiff) === 0 && compareNumStr(cand, best) < 0)
    ) {
      best = cand;
      bestDiff = diff;
    }
  }

  return best;
}

// Tests
