assert.strictEqual(nearestPalindrome('1'), '0');                 // single digit
assert.strictEqual(nearestPalindrome('9'), '8');                 // single digit high
assert.strictEqual(nearestPalindrome('10'), '9');                // power of ten
assert.strictEqual(nearestPalindrome('1000'), '999');            // larger power of ten
assert.strictEqual(nearestPalindrome('11'), '9');                // already palindromic
assert.strictEqual(nearestPalindrome('121'), '111');             // already palindromic
assert.strictEqual(nearestPalindrome('99'), '101');              // tie -> smaller diff winner
assert.strictEqual(nearestPalindrome('1283'), '1331');           // general case
assert.strictEqual(nearestPalindrome('1001'), '999');            // palindrome near lower boundary
assert.strictEqual(nearestPalindrome('12345678987654321'), '123456788887654321'); // very large input
assert.throws(() => nearestPalindrome(''), /non-empty string of digits/);
