```js
function removeComments(code) {
  if (code === '') return '';

  let result = '';
  let i = 0;
  let inLineComment = false;
  let inBlockComment = false;
  let inString = false;
  let stringQuote = '';

  while (i < code.length) {
    const char = code[i];
    const next = code[i + 1];

    if (inLineComment) {
      if (char === '\n') {
        inLineComment = false;
        result += char;
      }
      i += 1;
      continue;
    }

    if (inBlockComment) {
      if (char === '*' && next === '/') {
        inBlockComment = false;
        i += 2;
      } else {
        i += 1;
      }
      continue;
    }

    if (inString) {
      result += char;

      if (char === '\\' && i + 1 < code.length) {
        result += code[i + 1];
        i += 2;
        continue;
      }

      if (char === stringQuote) {
        inString = false;
        stringQuote = '';
      }

      i += 1;
      continue;
    }

    if (char === '"' || char === "'") {
      inString = true;
      stringQuote = char;
      result += char;
      i += 1;
      continue;
    }

    if (char === '/' && next === '/') {
      inLineComment = true;
      i += 2;
      continue;
    }

    if (char === '/' && next === '*') {
      inBlockComment = true;
      i += 2;
      continue;
    }

    result += char;
    i += 1;
  }

  return result;
}

module.exports = { removeComments };
```

