assert.strictEqual(evaluateRpn(['4', '5', '*']), 20);
assert.strictEqual(evaluateRpn(['7', '3', '/']), 2);
assert.strictEqual(evaluateRpn(['-7', '3', '/']), -2); // truncates toward zero
assert.strictEqual(evaluateRpn(['2', '1', '+', '3', '*']), 9);
