function romanToInt(input) {
  if (typeof input !== 'string') {
    throw new TypeError('Roman numeral must be a string');
  }

  const s = input.trim();
  if (!s) {
    throw new Error('Roman numeral cannot be empty');
  }
  if (!/^[ivxlcdm]+$/i.test(s)) {
    throw new Error('Roman numeral contains invalid characters');
  }

  const roman = s.toUpperCase();
  const values = {
    I: 1,
    V: 5,
    X: 10,
    L: 50,
    C: 100,
    D: 500,
    M: 1000,
  };

  const repeatable = new Set(['I', 'X', 'C', 'M']);
  const validSubtractive = new Set(['IV', 'IX', 'XL', 'XC', 'CD', 'CM']);

  let total = 0;
  let i = 0;
  let repeatCount = 1;

  while (i < roman.length) {
    const current = roman[i];
    const currentValue = values[current];
    const next = roman[i + 1];
    const nextValue = next ? values[next] : 0;

    if (i > 0 && roman[i] === roman[i - 1]) {
      repeatCount += 1;
    } else {
      repeatCount = 1;
    }

    if (!repeatable.has(current) && repeatCount > 1) {
      throw new Error(`Symbol ${current} cannot repeat`);
    }
    if (repeatable.has(current) && repeatCount > 3) {
      throw new Error(`Symbol ${current} cannot repeat more than 3 times`);
    }

    if (next && currentValue < nextValue) {
      const pair = current + next;

      if (repeatCount > 1) {
        throw new Error(`Invalid subtractive pattern: ${pair}`);
      }
      if (!validSubtractive.has(pair)) {
        throw new Error(`Invalid subtractive pair: ${pair}`);
      }

      total += nextValue - currentValue;
      i += 2;
      repeatCount = 1;
      continue;
    }

    total += currentValue;
    i += 1;
  }

  const canonical = intToRoman(total);
  if (canonical !== roman) {
    throw new Error(`Malformed Roman numeral: ${input}`);
  }

  return total;
}

function intToRoman(num) {
  const parts = [
    ['M', 1000],
    ['CM', 900],
    ['D', 500],
    ['CD', 400],
    ['C', 100],
    ['XC', 90],
    ['L', 50],
    ['XL', 40],
    ['X', 10],
    ['IX', 9],
    ['V', 5],
    ['IV', 4],
    ['I', 1],
  ];

  let result = '';
  let remaining = num;

  for (const [symbol, value] of parts) {
    while (remaining >= value) {
      result += symbol;
      remaining -= value;
    }
  }

  return result;
}
```

