```js
function knapsack01(items, capacity) {
  if (!Array.isArray(items)) {
    throw new TypeError('items must be an array');
  }
  if (!Number.isInteger(capacity) || capacity < 0) {
    throw new TypeError('capacity must be a non-negative integer');
  }

  const dp = Array(capacity + 1).fill(0);

  for (let i = 0; i < items.length; i += 1) {
    const item = items[i];

    if (item === null || typeof item !== 'object' || Array.isArray(item)) {
      throw new TypeError(`items[${i}] must be an object`);
    }

    const { weight, value } = item;

    if (!Number.isInteger(weight) || weight < 0) {
      throw new TypeError(`items[${i}].weight must be a non-negative integer`);
    }
    if (typeof value !== 'number' || Number.isNaN(value) || !Number.isFinite(value)) {
      throw new TypeError(`items[${i}].value must be a finite number`);
    }

    for (let w = capacity; w >= weight; w -= 1) {
      dp[w] = Math.max(dp[w], dp[w - weight] + value);
    }
  }

  return dp[capacity];
}
```

