  new Promise(resolve => setTimeout(() => resolve(value), ms));

async function taskA() {
  return delay(300, 'A');
}

async function taskB() {
  return delay(100, 'B');
}

async function taskC() {
  return delay(200, 'C');
}

runThreeTasks(taskA, taskB, taskC)
  .then(results => {
    console.log(results); // ['A', 'B', 'C']
  })
  .catch(err => {
    console.error(err);
  });
```

