```ts
import crypto from 'node:crypto'
import express from 'express'

type VerifyResult =
  | { ok: true; provider: string; eventId?: string; timestamp?: number }
  | { ok: false; status: number; code: string; message: string }

type ProviderConfig = {
  name: string
  header: string
  secret: string
  toleranceSec?: number
  buildPayload: (rawBody: Buffer, headers: Record<string, string>) => string | Buffer
  extractSignature: (headerValue: string) => string | null
  extractTimestamp?: (headerValue: string) => number | null
  digest?: 'sha256' | 'sha1'
}

function secureEqual(a: string, b: string) {
  const aBuf = Buffer.from(a)
  const bBuf = Buffer.from(b)
  return aBuf.length === bBuf.length && crypto.timingSafeEqual(aBuf, bBuf)
}

function hexHmac(secret: string, payload: string | Buffer, digest: 'sha256' | 'sha1' = 'sha256') {
  return crypto.createHmac(digest, secret).update(payload).digest('hex')
}

function verifySignature(rawBody: Buffer, headers: Record<string, string>, config: ProviderConfig): VerifyResult {
  const headerValue = headers[config.header.toLowerCase()]
  if (!headerValue) {
    return { ok: false, status: 401, code: 'missing_signature', message: `Missing ${config.header}` }
  }

  const signature = config.extractSignature(headerValue)
  if (!signature) {
    return { ok: false, status: 401, code: 'invalid_signature_header', message: 'Malformed signature header' }
  }

  const timestamp = config.extractTimestamp?.(headerValue)
  if (config.toleranceSec && timestamp) {
    const age = Math.abs(Math.floor(Date.now() / 1000) - timestamp)
    if (age > config.toleranceSec) {
      return { ok: false, status: 401, code: 'stale_timestamp', message: 'Signature timestamp outside tolerance window' }
    }
  }

  const expected = hexHmac(config.secret, config.buildPayload(rawBody, headers), config.digest)
  if (!secureEqual(expected, signature)) {
    return { ok: false, status: 401, code: 'signature_mismatch', message: 'Invalid signature' }
  }

  return {
    ok: true,
    provider: config.name,
    timestamp: timestamp ?? undefined,
    eventId: headers['x-event-id'] || headers['x-github-delivery'] || undefined,
  }
}

const providers: Record<string, ProviderConfig> = {
  stripe: {
    name: 'stripe',
    header: 'stripe-signature',
    secret: process.env.STRIPE_WEBHOOK_SECRET!,
    toleranceSec: 300,
    buildPayload: (rawBody, headers) => {
      const sig = headers['stripe-signature'] || ''
      const ts = sig.match(/(?:^|,)t=(\d+)/)?.[1]
      return `${ts}.${rawBody.toString('utf8')}`
    },
    extractSignature: (value) => value.match(/(?:^|,)v1=([a-f0-9]+)/i)?.[1] ?? null,
    extractTimestamp: (value) => {
      const ts = value.match(/(?:^|,)t=(\d+)/)?.[1]
      return ts ? Number(ts) : null
    },
  },
  github: {
    name: 'github',
    header: 'x-hub-signature-256',
    secret: process.env.GITHUB_WEBHOOK_SECRET!,
    buildPayload: (rawBody) => rawBody,
    extractSignature: (value) => value.replace(/^sha256=/, ''),
  },
  slack: {
    name: 'slack',
    header: 'x-slack-signature',
    secret: process.env.SLACK_SIGNING_SECRET!,
    toleranceSec: 300,
    buildPayload: (rawBody, headers) => {
      const ts = headers['x-slack-request-timestamp']
      return `v0:${ts}:${rawBody.toString('utf8')}`
    },
    extractSignature: (value) => value.replace(/^v0=/, ''),
    extractTimestamp: (_value) => null,
  },
}

const app = express()

app.use(
  express.raw({
    type: '*/*',
    verify: (req: any, _res, buf) => {
      req.rawBody = Buffer.from(buf)
    },
  })
)

app.post('/webhooks/:provider', (req: any, res) => {
  const provider = providers[req.params.provider]
  if (!provider) {
    return res.status(404).json({ error: 'unknown_provider' })
  }

  const headers = Object.fromEntries(
    Object.entries(req.headers).map(([k, v]) => [k.toLowerCase(), Array.isArray(v) ? v.join(',') : String(v ?? '')])
  )

  const result = verifySignature(req.rawBody, headers, provider)
  if (!result.ok) {
    return res.status(result.status).json({ error: result.code, message: result.message })
  }

  res.status(200).json({ verified: true, provider: result.provider, eventId: result.eventId })
})

app.listen(3000)
```

### Service design
- Capture the **raw request body** before any JSON parsing. Signature verification must run on exact bytes received.
- Normalize headers to lowercase once.
- Define a **provider adapter** per webhook source:
  - which header contains the signature
  - how to build the signed payload
  - how to extract timestamp/signature parts
  - replay tolerance window
  - HMAC digest algorithm
- Use `crypto.timingSafeEqual` to avoid timing leaks.
- Reject missing, malformed, stale, or mismatched signatures with `401`.
- Only parse/process the event after verification succeeds.

### Recommended API shape
- `POST /webhooks/:provider`
- `verifySignature(rawBody, headers, providerConfig)` as a pure function
- optional `idempotencyStore.has(eventId)` check after verification to prevent duplicate processing

### Security checklist
- Store signing secrets in a secret manager, not source code.
- Support **secret rotation** by allowing multiple active secrets per provider.
- Enforce small body size limits.
- Log verification failures without logging secrets or full payloads.
- Add replay protection using timestamp + event ID.
- Return generic failure messages externally; keep detailed reason in internal logs.

### Production additions
- Multi-secret verification during rotation:
```ts
function verifyAgainstAnySecret(payload: string | Buffer, signature: string, secrets: string[]) {
  return secrets.some((secret) => secureEqual(hexHmac(secret, payload), signature))
}
```
- Queue verified events for async handling.
- Persist event ID + provider + received time for deduplication.
- Emit metrics: verification success/failure, stale timestamp count, per-provider latency.
- Add contract tests using official provider examples.

If you want, I can turn this into a full RFC with architecture, threat model, sequence diagram, and test plan.

695.answer:
## URL Safety Scanner

### Goal
Classify a URL as **safe, suspicious, or malicious** using fast static checks plus optional reputation lookups, then explain why.

### Core pipeline
1. **Normalize input**
   - Trim whitespace
   - Parse with a real URL parser
   - Lowercase host
   - Convert IDN to punycode and keep original for display
   - Strip fragments
   - Canonicalize default ports

2. **Extract features**
   - Scheme: `http`, `https`, `ftp`, `javascript`, `data`
   - Host: domain, subdomain depth, TLD, IP-literal, punycode
   - Path/query: encoded chars, dangerous extensions, keyword bait (`login`, `verify`, `reset-password`)
   - Length features: full URL length, host length, path length
   - Structure: number of dots, hyphens, redirects params, `@`, repeated slashes

3. **Static risk checks**
   - Non-HTTP schemes → high risk
   - Raw IP address instead of domain → suspicious
   - Homoglyph / punycode domain → suspicious
   - Very long URL or host → suspicious
   - Excessive subdomains / hyphens → suspicious
   - `@` in authority → high risk
   - Known URL shortener → suspicious unless expanded
   - Mismatch patterns like `paypal.com.evil.tld` → high risk
   - Sensitive-brand keywords in unrelated domains → suspicious
   - File delivery types: `.exe`, `.scr`, `.zip`, `.js` → elevated risk depending on context

4. **Reputation checks (optional but valuable)**
   - Safe Browsing / VirusTotal / URLHaus / PhishTank
   - Domain age via WHOIS/RDAP
   - DNS presence / MX / ASN consistency
   - TLS certificate validity and SAN match

5. **Decision engine**
   - Weighted score or rules:
     - `0-29`: Safe
     - `30-69`: Suspicious
     - `70+`: Malicious
   - Also return triggered rules for explainability

6. **Output**
   - Verdict
   - Risk score
   - Reasons
   - Normalized URL
   - Recommended action: allow, warn, block

### Example rule set
```ts
interface ScanResult {
  verdict: 'safe' | 'suspicious' | 'malicious';
  score: number;
  normalizedUrl: string;
  reasons: string[];
  signals: Record<string, boolean | number | string>;
  action: 'allow' | 'warn' | 'block';
}
```

```ts
function scoreUrl(u: URL): ScanResult {
  let score = 0;
  const reasons: string[] = [];
  const host = u.hostname.toLowerCase();
  const path = u.pathname.toLowerCase();

  const add = (points: number, reason: string) => {
    score += points;
    reasons.push(reason);
  };

  if (!['http:', 'https:'].includes(u.protocol)) add(80, 'Non-web URL scheme');
  if (/^\d{1,3}(\.\d{1,3}){3}$/.test(host)) add(30, 'Uses raw IPv4 address');
  if (host.includes('xn--')) add(25, 'Punycode/IDN hostname');
  if (host.split('.').length > 4) add(20, 'Excessive subdomain depth');
  if (host.includes('@')) add(80, 'Contains @ in authority');
  if (u.href.length > 150) add(15, 'Unusually long URL');
  if (/(login|verify|reset|secure|update|account)/.test(path) && !/(trusted-domain\.com)$/.test(host)) {
    add(20, 'Credential-themed path on unrelated domain');
  }
  if (/\.(exe|scr|bat|js|zip)$/i.test(path)) add(40, 'Direct download of risky file type');

  const verdict = score >= 70 ? 'malicious' : score >= 30 ? 'suspicious' : 'safe';
  const action = verdict === 'malicious' ? 'block' : verdict === 'suspicious' ? 'warn' : 'allow';

  return {
    verdict,
    score,
    normalizedUrl: u.toString(),
    reasons,
    action,
    signals: {
      protocol: u.protocol,
      host,
      urlLength: u.href.length,
      subdomainDepth: host.split('.').length - 2,
    },
  };
}
```

### Recommended architecture
- **Parser/Normalizer**
- **Feature Extractor**
- **Rule Engine**
- **Reputation Providers**
- **Verdict Composer**
- **API/UI layer**

### API shape
```http
POST /scan-url
Content-Type: application/json

{ "url": "https://example.com/login" }
```

Response:
```json
{
  "verdict": "suspicious",
  "score": 48,
  "action": "warn",
  "reasons": [
    "Credential-themed path on unrelated domain",
    "Unusually long URL"
  ],
  "normalizedUrl": "https://example.com/login"
}
```

### Important safety notes
- Do **not** fetch or render arbitrary URLs by default.
- Prefer passive analysis first.
- If you add active checks, isolate them in a sandbox.
- Keep a clear allowlist for internal domains.
- Log rule hits for analyst review.

### Good MVP
Build the scanner in 2 stages:
1. **MVP**: parser + static heuristics + score output
2. **V2**: reputation APIs, redirect expansion, domain age, certificate checks

If you want, I can also turn this into a **full spec**, **Node/TypeScript implementation**, or a **CLI/web app prototype**.

