```js
import fs from 'node:fs/promises';

async function fetchAllUsers() {
  const seenIds = new Set();
  const rows = [];
  let page = 1;

  while (true) {
    const res = await fetch(`https://api.example.com/v1/users?page=${page}`);

    if (!res.ok) {
      throw new Error(`Request failed for page ${page}: ${res.status} ${res.statusText}`);
    }

    const body = await res.json();
    const users = body.data;

    if (!Array.isArray(users)) {
      throw new Error(`Invalid response on page ${page}: "data" must be an array`);
    }

    if (users.length === 0) {
      break;
    }

    for (const user of users) {
      const { id, full_name, created_at } = user;

      if (seenIds.has(id)) {
        throw new Error(`Duplicate user id found across pages: ${id}`);
      }

      seenIds.add(id);
      rows.push({
        id,
        name: full_name,
        created_at,
      });
    }

    page += 1;
  }

  return rows;
}

function escapeCsv(value) {
  const str = String(value ?? '');
  if (/[",\n]/.test(str)) {
    return `"${str.replace(/"/g, '""')}"`;
  }
  return str;
}

async function writeUsersCsv(filePath, users) {
  const header = ['id', 'name', 'created_at'];
  const lines = [
    header.join(','),
    ...users.map((user) =>
      [user.id, user.name, user.created_at].map(escapeCsv).join(',')
    ),
  ];

  await fs.writeFile(filePath, `${lines.join('\n')}\n`, 'utf8');
}

async function main() {
  const users = await fetchAllUsers();
  await writeUsersCsv('users.csv', users);
  console.log(`Wrote ${users.length} users to users.csv`);
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});
```

