766.answer:
Branch and bound reduces search by exploring partial solutions, computing a lower bound on their best possible completion cost, and pruning any branch whose bound is already worse than the best complete solution found so far.

For TSP, a simple version is:
- A **branch** = a partial tour, like `0 -> 2 -> ...`
- A **bound** = optimistic minimum possible total cost from that partial tour
- **Prune** when that optimistic cost is `>= bestCost`

A common simplified bound uses row minima from a reduced cost matrix:
1. Start from the original matrix.
2. Set diagonals to infinity.
3. Reduce each row by its minimum, then each column by its minimum.
4. The sum of reductions is a lower bound.
5. When choosing edge `i -> j`, forbid:
   - row `i` (can't leave `i` again)
   - column `j` (can't enter `j` again)
   - edge `j -> start` until the end
6. Reduce again; the new reduction cost contributes to the new bound.

Here is a simplified Java implementation for **4 cities** using cost-matrix pruning:

```java
import java.util.*;

public class TSPBranchAndBound4 {
    static final int INF = 1_000_000;
    static final int N = 4;

    static int bestCost = INF;
    static List<Integer> bestPath = new ArrayList<>();

    static class Node {
        int[][] matrix;
        int cost;      // lower bound so far
        int level;     // number of cities in path - 1
        int city;      // current city
        List<Integer> path;

        Node(int[][] matrix, int cost, int level, int city, List<Integer> path) {
            this.matrix = matrix;
            this.cost = cost;
            this.level = level;
            this.city = city;
            this.path = path;
        }
    }

    static int[][] copyMatrix(int[][] m) {
        int[][] copy = new int[N][N];
        for (int i = 0; i < N; i++) {
            System.arraycopy(m[i], 0, copy[i], 0, N);
        }
        return copy;
    }

    static int reduceMatrix(int[][] matrix) {
        int reductionCost = 0;

        // Row reduction
        for (int i = 0; i < N; i++) {
            int rowMin = INF;
            for (int j = 0; j < N; j++) {
                rowMin = Math.min(rowMin, matrix[i][j]);
            }
            if (rowMin != INF && rowMin > 0) {
                for (int j = 0; j < N; j++) {
                    if (matrix[i][j] != INF) {
                        matrix[i][j] -= rowMin;
                    }
                }
                reductionCost += rowMin;
            }
        }

        // Column reduction
        for (int j = 0; j < N; j++) {
            int colMin = INF;
            for (int i = 0; i < N; i++) {
                colMin = Math.min(colMin, matrix[i][j]);
            }
            if (colMin != INF && colMin > 0) {
                for (int i = 0; i < N; i++) {
                    if (matrix[i][j] != INF) {
                        matrix[i][j] -= colMin;
                    }
                }
                reductionCost += colMin;
            }
        }

        return reductionCost;
    }

    static Node createChild(Node parent, int nextCity, int startCity) {
        int[][] childMatrix = copyMatrix(parent.matrix);

        // Cost of taking edge parent.city -> nextCity in reduced matrix
        int edgeCost = parent.matrix[parent.city][nextCity];

        // Invalidate row of current city and column of next city
        for (int k = 0; k < N; k++) {
            childMatrix[parent.city][k] = INF;
            childMatrix[k][nextCity] = INF;
        }

        // Prevent returning to start too early
        childMatrix[nextCity][startCity] = INF;

        int reductionCost = reduceMatrix(childMatrix);

        List<Integer> newPath = new ArrayList<>(parent.path);
        newPath.add(nextCity);

        int newCost = parent.cost + edgeCost + reductionCost;
        return new Node(childMatrix, newCost, parent.level + 1, nextCity, newPath);
    }

    static void solve(int[][] costMatrix, int startCity) {
        int[][] rootMatrix = copyMatrix(costMatrix);
        for (int i = 0; i < N; i++) {
            rootMatrix[i][i] = INF;
        }

        int rootCost = reduceMatrix(rootMatrix);
        PriorityQueue<Node> pq = new PriorityQueue<>(Comparator.comparingInt(n -> n.cost));
        pq.add(new Node(rootMatrix, rootCost, 0, startCity, new ArrayList<>(List.of(startCity))));

        while (!pq.isEmpty()) {
            Node current = pq.poll();

            if (current.cost >= bestCost) {
                continue; // prune
            }

            if (current.level == N - 1) {
                int lastCity = current.city;
                int tourCost = actualTourCost(costMatrix, current.path, startCity);
                if (tourCost < bestCost) {
                    bestCost = tourCost;
                    bestPath = new ArrayList<>(current.path);
                    bestPath.add(startCity);
                }
                continue;
            }

            for (int nextCity = 0; nextCity < N; nextCity++) {
                if (!current.path.contains(nextCity) && current.matrix[current.city][nextCity] != INF) {
                    Node child = createChild(current, nextCity, startCity);
                    if (child.cost < bestCost) {
                        pq.add(child);
                    }
                }
            }
        }
    }

    static int actualTourCost(int[][] costMatrix, List<Integer> path, int startCity) {
        int total = 0;
        for (int i = 0; i < path.size() - 1; i++) {
            total += costMatrix[path.get(i)][path.get(i + 1)];
        }
        total += costMatrix[path.get(path.size() - 1)][startCity];
        return total;
    }

    public static void main(String[] args) {
        int[][] costMatrix = {
            {INF, 10, 15, 20},
            {10, INF, 35, 25},
            {15, 35, INF, 30},
            {20, 25, 30, INF}
        };

        solve(costMatrix, 0);

        System.out.println("Minimum tour cost: " + bestCost);
        System.out.println("Best path: " + bestPath);
    }
}
```

Expected result for this matrix:
- Minimum cost: `80`
- One optimal path: `[0, 1, 3, 2, 0]`

A few notes:
- This is intentionally **simplified for 4 cities** and clarity.
- `current.path.contains(nextCity)` is fine here, though for larger `N` you'd use a boolean visited array.
- The bound comes from the **reduced matrix**, while the final answer uses the **original cost matrix**.

