772.answer:
Prim’s algorithm grows a minimum spanning tree by starting from any node and repeatedly adding the cheapest edge that connects a visited node to an unvisited node. A min-priority queue makes this efficient: push all outgoing edges from the current tree, pop the lightest edge, and if it leads to a new vertex, add its weight to the answer and push that vertex’s outgoing edges. Repeating until all reachable vertices are added yields the MST for a connected graph.

Time complexity is **O((V + E) log V)** or **O(E log E)** depending on the exact heap formulation, and space complexity is **O(V + E)** for the graph plus heap.

```go
package main

import (
	"container/heap"
	"fmt"
)

type Edge struct {
	to     int
	weight int
}

type Item struct {
	node   int
	weight int
}

type MinHeap []Item

func (h MinHeap) Len() int            { return len(h) }
func (h MinHeap) Less(i, j int) bool  { return h[i].weight < h[j].weight }
func (h MinHeap) Swap(i, j int)       { h[i], h[j] = h[j], h[i] }
func (h *MinHeap) Push(x any)         { *h = append(*h, x.(Item)) }
func (h *MinHeap) Pop() any {
	old := *h
	n := len(old)
	item := old[n-1]
	*h = old[:n-1]
	return item
}

// PrimMST returns the total MST weight for a connected, undirected graph.
// n is the number of vertices labeled [0..n-1].
func PrimMST(n int, graph [][]Edge) int {
	visited := make([]bool, n)
	pq := &MinHeap{}
	heap.Init(pq)

	// Start from node 0 with cost 0.
	heap.Push(pq, Item{node: 0, weight: 0})

	totalWeight := 0
	visitedCount := 0

	for pq.Len() > 0 && visitedCount < n {
		item := heap.Pop(pq).(Item)
		u := item.node

		if visited[u] {
			continue
		}

		visited[u] = true
		visitedCount++
		totalWeight += item.weight

		for _, e := range graph[u] {
			if !visited[e.to] {
				heap.Push(pq, Item{node: e.to, weight: e.weight})
			}
		}
	}

	if visitedCount != n {
		panic("graph is disconnected; MST does not exist")
	}

	return totalWeight
}

func addUndirectedEdge(graph [][]Edge, u, v, w int) {
	graph[u] = append(graph[u], Edge{to: v, weight: w})
	graph[v] = append(graph[v], Edge{to: u, weight: w})
}

func main() {
	n := 5
	graph := make([][]Edge, n)

	addUndirectedEdge(graph, 0, 1, 2)
	addUndirectedEdge(graph, 0, 3, 6)
	addUndirectedEdge(graph, 1, 2, 3)
	addUndirectedEdge(graph, 1, 3, 8)
	addUndirectedEdge(graph, 1, 4, 5)
	addUndirectedEdge(graph, 2, 4, 7)
	addUndirectedEdge(graph, 3, 4, 9)

	fmt.Println(PrimMST(n, graph)) // 16
}
```

