A binary search tree (BST) is a binary tree where, for every node, all values in the left subtree are smaller and all values in the right subtree are larger. This ordering makes search, insert, and delete efficient on average: each step discards half the remaining tree, so typical operations are **O(log n)** when the tree is balanced, but can degrade to **O(n)** if it becomes skewed.

Here’s a simple Python implementation with `insert`, `search`, and in-order traversal:

```python
class Node:
    def __init__(self, value):
        self.value = value
        self.left = None
        self.right = None


class BinarySearchTree:
    def __init__(self):
        self.root = None

    def insert(self, value):
        if self.root is None:
            self.root = Node(value)
            return

        current = self.root
        while True:
            if value < current.value:
                if current.left is None:
                    current.left = Node(value)
                    return
                current = current.left
            elif value > current.value:
                if current.right is None:
                    current.right = Node(value)
                    return
                current = current.right
            else:
                return  # ignore duplicates

    def search(self, value):
        current = self.root
        while current is not None:
            if value == current.value:
                return True
            if value < current.value:
                current = current.left
            else:
                current = current.right
        return False

    def in_order(self):
        result = []

        def traverse(node):
            if node is None:
                return
            traverse(node.left)
            result.append(node.value)
            traverse(node.right)

        traverse(self.root)
        return result


# Example usage
bst = BinarySearchTree()
for value in [8, 3, 10, 1, 6, 14, 4, 7, 13]:
    bst.insert(value)

print(bst.search(6))      # True
print(bst.search(2))      # False
print(bst.in_order())     # [1, 3, 4, 6, 7, 8, 10, 13, 14]
```

`in_order()` visits **left -> root -> right**, which returns BST values in sorted order.

