A **heap** is a tree-based data structure usually stored in an array.

For a **min-heap**:
- The smallest element is always at the root.
- Every parent is `<=` its children.
- It is usually a **complete binary tree**, so insertion/removal stay efficient.

With array storage:
- parent of `i` is `(i - 1) / 2`
- left child is `2 * i + 1`
- right child is `2 * i + 2`

Common operations:
- **push(x)**: add to the end, then bubble up — `O(log n)`
- **top()**: read minimum element — `O(1)`
- **pop()**: remove minimum, move last element to root, then bubble down — `O(log n)`

Here’s a simple C++ min-heap with `push`, `top`, and `pop`:

```cpp
#include <iostream>
#include <vector>
#include <stdexcept>
using namespace std;

class MinHeap {
private:
    vector<int> heap;

    void heapifyUp(int index) {
        while (index > 0) {
            int parent = (index - 1) / 2;
            if (heap[parent] <= heap[index]) break;
            swap(heap[parent], heap[index]);
            index = parent;
        }
    }

    void heapifyDown(int index) {
        int n = heap.size();
        while (true) {
            int left = 2 * index + 1;
            int right = 2 * index + 2;
            int smallest = index;

            if (left < n && heap[left] < heap[smallest]) {
                smallest = left;
            }
            if (right < n && heap[right] < heap[smallest]) {
                smallest = right;
            }
            if (smallest == index) break;

            swap(heap[index], heap[smallest]);
            index = smallest;
        }
    }

public:
    void push(int value) {
        heap.push_back(value);
        heapifyUp(heap.size() - 1);
    }

    int top() const {
        if (heap.empty()) {
            throw runtime_error("Heap is empty");
        }
        return heap[0];
    }

    void pop() {
        if (heap.empty()) {
            throw runtime_error("Heap is empty");
        }

        heap[0] = heap.back();
        heap.pop_back();

        if (!heap.empty()) {
            heapifyDown(0);
        }
    }

    bool empty() const {
        return heap.empty();
    }

    int size() const {
        return heap.size();
    }
};

int main() {
    MinHeap h;

    h.push(10);
    h.push(4);
    h.push(15);
    h.push(2);
    h.push(8);

    cout << h.top() << "\n"; // 2
    h.pop();
    cout << h.top() << "\n"; // 4
    h.pop();
    cout << h.top() << "\n"; // 8

    return 0;
}
```

