The Template Method pattern defines the skeleton of an algorithm in a base class while letting subclasses override specific steps. It’s useful when multiple workflows share the same high-level process but differ in a few details.

For a data parser, the base class can enforce a common flow like:
1. Validate input
2. Preprocess raw text
3. Parse records
4. Postprocess results

Subclasses then customize the parsing step for CSV vs JSON without changing the overall algorithm.

### C# example
```csharp
using System;
using System.Collections.Generic;
using System.Linq;
using System.Text.Json;

public abstract class DataParser
{
    public List<Dictionary<string, string>> Parse(string input)
    {
        Validate(input);
        string normalized = Preprocess(input);
        var records = ParseCore(normalized);
        return Postprocess(records);
    }

    protected virtual void Validate(string input)
    {
        if (string.IsNullOrWhiteSpace(input))
            throw new ArgumentException("Input cannot be null or empty.");
    }

    protected virtual string Preprocess(string input)
    {
        return input.Trim();
    }

    protected abstract List<Dictionary<string, string>> ParseCore(string input);

    protected virtual List<Dictionary<string, string>> Postprocess(List<Dictionary<string, string>> records)
    {
        return records;
    }
}

public sealed class CsvDataParser : DataParser
{
    protected override List<Dictionary<string, string>> ParseCore(string input)
    {
        var lines = input
            .Split(new[] { "\r\n", "\n" }, StringSplitOptions.RemoveEmptyEntries);

        if (lines.Length < 2)
            return new List<Dictionary<string, string>>();

        var headers = lines[0].Split(',').Select(h => h.Trim()).ToArray();
        var results = new List<Dictionary<string, string>>();

        for (int i = 1; i < lines.Length; i++)
        {
            var values = lines[i].Split(',').Select(v => v.Trim()).ToArray();
            var record = new Dictionary<string, string>();

            for (int j = 0; j < headers.Length; j++)
            {
                record[headers[j]] = j < values.Length ? values[j] : string.Empty;
            }

            results.Add(record);
        }

        return results;
    }
}

public sealed class JsonDataParser : DataParser
{
    protected override List<Dictionary<string, string>> ParseCore(string input)
    {
        using var document = JsonDocument.Parse(input);

        if (document.RootElement.ValueKind != JsonValueKind.Array)
            throw new FormatException("Expected a JSON array of objects.");

        var results = new List<Dictionary<string, string>>();

        foreach (var element in document.RootElement.EnumerateArray())
        {
            if (element.ValueKind != JsonValueKind.Object)
                continue;

            var record = new Dictionary<string, string>();

            foreach (var property in element.EnumerateObject())
            {
                record[property.Name] = property.Value.ToString();
            }

            results.Add(record);
        }

        return results;
    }
}

public static class Program
{
    public static void Main()
    {
        string csv = @"name,age
Alice,30
Bob,25";

        string json = @"[
  { ""name"": ""Alice"", ""age"": 30 },
  { ""name"": ""Bob"", ""age"": 25 }
]";

        DataParser csvParser = new CsvDataParser();
        DataParser jsonParser = new JsonDataParser();

        var csvRecords = csvParser.Parse(csv);
        var jsonRecords = jsonParser.Parse(json);

        Print("CSV", csvRecords);
        Print("JSON", jsonRecords);
    }

    private static void Print(string label, List<Dictionary<string, string>> records)
    {
        Console.WriteLine($"{label} results:");
        foreach (var record in records)
        {
            Console.WriteLine(string.Join(", ", record.Select(kvp => $"{kvp.Key}={kvp.Value}")));
        }
        Console.WriteLine();
    }
}
```

### Why this is Template Method
- `DataParser.Parse()` is the template method.
- It defines the fixed algorithm structure.
- `ParseCore()` is the required customizable step.
- `Validate()`, `Preprocess()`, and `Postprocess()` are hooks subclasses may override if needed.

If you want, I can also provide a version that returns strongly typed records instead of `Dictionary<string, string>`.

