The repository pattern separates data access from business logic by putting persistence operations behind a small interface. Your application works with a repository abstraction instead of talking directly to a database, API, or storage layer. That makes code easier to test, swap storage implementations, and keep domain logic focused on behavior rather than queries.

A repository usually exposes collection-like operations for an aggregate or entity type, such as add, get by id, and list all. In Python, an in-memory repository is a simple way to implement this for tests or small apps.
```python
from dataclasses import dataclass
from typing import Dict, List, Optional, Protocol


@dataclass(frozen=True)
class User:
    id: int
    name: str


class UserRepository(Protocol):
    def add(self, user: User) -> None:
        ...

    def get_by_id(self, user_id: int) -> Optional[User]:
        ...

    def list_all(self) -> List[User]:
        ...


class InMemoryUserRepository:
    def __init__(self) -> None:
        self._users: Dict[int, User] = {}

    def add(self, user: User) -> None:
        self._users[user.id] = user

    def get_by_id(self, user_id: int) -> Optional[User]:
        return self._users.get(user_id)

    def list_all(self) -> List[User]:
        return list(self._users.values())


if __name__ == "__main__":
    repo: UserRepository = InMemoryUserRepository()

    repo.add(User(id=1, name="Alice"))
    repo.add(User(id=2, name="Bob"))

    print(repo.get_by_id(1))
    print(repo.list_all())
```

