A token bucket rate limiter keeps a bucket of tokens that refills at a fixed rate up to a maximum capacity. Each request consumes one or more tokens. If enough tokens are available, the request is allowed; otherwise it is rejected. This permits short bursts up to the bucket capacity while still enforcing a long-term average rate equal to the refill rate.

In practice:
- **capacity** = maximum burst size
- **refill rate** = tokens added per second
- **tokens** = current budget
- On each request, first compute how much time passed since the last update, add `elapsed * refillRate` tokens, clamp to `capacity`, then check whether enough tokens remain.

Go implementation:

```go
package main

import (
	"fmt"
	"sync"
	"time"
)

type TokenBucket struct {
	mu         sync.Mutex
	capacity   float64
	tokens     float64
	refillRate float64 // tokens per second
	lastRefill time.Time
}

func NewTokenBucket(capacity int, refillRate float64) *TokenBucket {
	if capacity <= 0 {
		panic("capacity must be > 0")
	}
	if refillRate <= 0 {
		panic("refillRate must be > 0")
	}

	now := time.Now()
	return &TokenBucket{
		capacity:   float64(capacity),
		tokens:     float64(capacity),
		refillRate: refillRate,
		lastRefill: now,
	}
}

func (tb *TokenBucket) Allow(tokens float64) bool {
	if tokens <= 0 {
		return true
	}

	tb.mu.Lock()
	defer tb.mu.Unlock()

	tb.refill()

	if tb.tokens < tokens {
		return false
	}

	tb.tokens -= tokens
	return true
}

func (tb *TokenBucket) refill() {
	now := time.Now()
	elapsed := now.Sub(tb.lastRefill).Seconds()
	if elapsed <= 0 {
		return
	}

	tb.tokens += elapsed * tb.refillRate
	if tb.tokens > tb.capacity {
		tb.tokens = tb.capacity
	}
	tb.lastRefill = now
}

func main() {
	limiter := NewTokenBucket(5, 2) // capacity=5, refill=2 tokens/sec

	for i := 1; i <= 10; i++ {
		allowed := limiter.Allow(1)
		fmt.Printf("request %d allowed=%v\n", i, allowed)
		if i == 5 {
			time.Sleep(1500 * time.Millisecond) // let some tokens refill
		}
	}
}
```

