Consistent hashing places both nodes and keys on the same circular hash space, then assigns each key to the first node clockwise from the key’s position. When a node is added or removed, only the keys that fall near that node usually move, which makes it much more stable than modulo-based sharding.

Virtual nodes improve balance by placing each physical node on the ring multiple times under different hashes. That spreads ownership more evenly and reduces hotspots, especially when the number of physical nodes is small.

Here’s a simple Python implementation for string keys and node names:

```python
from __future__ import annotations

import bisect
import hashlib
from typing import Dict, List, Optional


class ConsistentHashRing:
    def __init__(self, nodes: Optional[List[str]] = None, replicas: int = 100) -> None:
        if replicas <= 0:
            raise ValueError("replicas must be > 0")

        self.replicas = replicas
        self.ring: List[int] = []
        self._hash_to_node: Dict[int, str] = {}
        self._nodes: set[str] = set()

        for node in nodes or []:
            self.add_node(node)

    @staticmethod
    def _hash(value: str) -> int:
        digest = hashlib.sha256(value.encode("utf-8")).digest()
        return int.from_bytes(digest[:8], byteorder="big", signed=False)

    def add_node(self, node: str) -> None:
        if node in self._nodes:
            return

        self._nodes.add(node)
        for replica in range(self.replicas):
            vnode_key = f"{node}#{replica}"
            h = self._hash(vnode_key)

            if h in self._hash_to_node:
                raise ValueError(f"hash collision for virtual node {vnode_key}")

            bisect.insort(self.ring, h)
            self._hash_to_node[h] = node

    def remove_node(self, node: str) -> None:
        if node not in self._nodes:
            return

        self._nodes.remove(node)
        for replica in range(self.replicas):
            vnode_key = f"{node}#{replica}"
            h = self._hash(vnode_key)

            idx = bisect.bisect_left(self.ring, h)
            if idx < len(self.ring) and self.ring[idx] == h:
                self.ring.pop(idx)
                del self._hash_to_node[h]

    def get_node(self, key: str) -> str:
        if not self.ring:
            raise ValueError("ring is empty")

        h = self._hash(key)
        idx = bisect.bisect(self.ring, h)
        if idx == len(self.ring):
            idx = 0
        return self._hash_to_node[self.ring[idx]]

    def get_ring_snapshot(self) -> List[tuple[int, str]]:
        return [(h, self._hash_to_node[h]) for h in self.ring]


if __name__ == "__main__":
    ring = ConsistentHashRing(["node-a", "node-b", "node-c"], replicas=50)

    keys = ["user:1", "user:2", "session:abc", "order:99"]
    for key in keys:
        print(f"{key} -> {ring.get_node(key)}")

    print("Adding node-d...")
    ring.add_node("node-d")
    for key in keys:
        print(f"{key} -> {ring.get_node(key)}")
```

How it works:
- Each node is represented `replicas` times as `node#0`, `node#1`, etc.
- Each key is hashed once onto the same ring.
- Lookup uses binary search to find the first virtual node clockwise.
- If the search goes past the end, it wraps to the start of the ring.

