function flattenObject(input) {
  const out = {};

  const escapeKey = (key) => String(key).replace(/\\/g, '\\\\').replace(/\./g, '\\.');

  const visit = (value, path) => {
    if (Array.isArray(value)) {
      if (value.length === 0) {
        out[path] = [];
        return;
      }
      value.forEach((item, index) => {
        const nextPath = path ? `${path}.${index}` : String(index);
        visit(item, nextPath);
      });
      return;
    }

    if (value && typeof value === 'object') {
      const keys = Object.keys(value);
      if (keys.length === 0) {
        out[path] = {};
        return;
      }
      for (const key of keys) {
        const escaped = escapeKey(key);
        const nextPath = path ? `${path}.${escaped}` : escaped;
        visit(value[key], nextPath);
      }
      return;
    }

    out[path] = value;
  };

  visit(input, '');
  return out;
}
```

