function addMoney(a, b) {
  const parse = (s) => {
    const sign = s.startsWith('-') ? -1 : 1;
    const raw = (s[0] === '-' || s[0] === '+') ? s.slice(1) : s;
    const [wholePart, fracPart = ''] = raw.split('.');
    const scale = fracPart.length;
    const digits = (wholePart || '0') + fracPart;
    return { value: sign * BigInt(digits || '0'), scale };
  };

  const x = parse(a);
  const y = parse(b);
  const scale = Math.max(x.scale, y.scale);
  const pow10 = (n) => 10n ** BigInt(n);

  const xv = x.value * pow10(scale - x.scale);
  const yv = y.value * pow10(scale - y.scale);
  const sum = xv + yv;

  const negative = sum < 0n;
  const abs = negative ? -sum : sum;
  let digits = abs.toString();

  if (scale === 0) return (negative ? '-' : '') + digits;

  if (digits.length <= scale) {
    digits = digits.padStart(scale + 1, '0');
  }

  const whole = digits.slice(0, -scale) || '0';
  const frac = digits.slice(-scale);
  return `${negative ? '-' : ''}${whole}.${frac}`;
}

