  const aParts = splitInterval(a);
  const bParts = splitInterval(b);

  for (const aPart of aParts) {
    for (const bPart of bParts) {
      if (hasPositiveOverlap(
        { ...aPart.start, isStart: true },
        { ...aPart.end, isStart: false },
        { ...bPart.start, isStart: true },
        { ...bPart.end, isStart: false },
      )) {
        return true;
      }

      if (
        aPart.start.time === aPart.end.time &&
        containsPoint(aPart.start.time, bPart) &&
        aPart.start.inclusive &&
        aPart.end.inclusive
      ) {
        return true;
      }

      if (
        bPart.start.time === bPart.end.time &&
        containsPoint(bPart.start.time, aPart) &&
        bPart.start.inclusive &&
        bPart.end.inclusive
      ) {
        return true;
      }
    }
  }

  return false;
}
```

Example shape:

```js
