type PaginationResult = {
  page: number;
  pageSize: number;
  totalItems: bigint;
  totalPages: bigint;
  hasPrevious: boolean;
  hasNext: boolean;
  startIndex: bigint | null;
  endIndex: bigint | null;
  isValid: boolean;
  error: 'INVALID_PAGE_SIZE' | 'INVALID_PAGE_NUMBER' | null;
};

export function paginate(
  totalItems: bigint | number,
  page: number,
  pageSize: number,
): PaginationResult {
  const total = typeof totalItems === 'bigint' ? totalItems : BigInt(totalItems);

  if (!Number.isInteger(pageSize) || pageSize <= 0) {
    return {
      page,
      pageSize,
      totalItems: total,
      totalPages: 0n,
      hasPrevious: false,
      hasNext: false,
      startIndex: null,
      endIndex: null,
      isValid: false,
      error: 'INVALID_PAGE_SIZE',
    };
  }

  if (!Number.isInteger(page) || page < 1) {
    return {
      page,
      pageSize,
      totalItems: total,
      totalPages: (total + BigInt(pageSize) - 1n) / BigInt(pageSize),
      hasPrevious: false,
      hasNext: false,
      startIndex: null,
      endIndex: null,
      isValid: false,
      error: 'INVALID_PAGE_NUMBER',
    };
  }

  const size = BigInt(pageSize);
  const totalPages = total === 0n ? 0n : (total + size - 1n) / size;

  if (total === 0n) {
    return {
      page,
      pageSize,
      totalItems: 0n,
      totalPages: 0n,
      hasPrevious: false,
      hasNext: false,
      startIndex: null,
      endIndex: null,
      isValid: true,
      error: null,
    };
  }

  const pageBig = BigInt(page);
  const startIndex = (pageBig - 1n) * size;

  if (pageBig > totalPages) {
    return {
      page,
      pageSize,
      totalItems: total,
      totalPages,
      hasPrevious: totalPages > 0n,
      hasNext: false,
      startIndex: null,
      endIndex: null,
      isValid: false,
      error: 'INVALID_PAGE_NUMBER',
    };
  }

  const endIndex = startIndex + size - 1n > total - 1n ? total - 1n : startIndex + size - 1n;

  return {
    page,
    pageSize,
    totalItems: total,
    totalPages,
    hasPrevious: page > 1,
    hasNext: pageBig < totalPages,
    startIndex,
    endIndex,
    isValid: true,
    error: null,
  };
}
```

Exact invalid-request behavior:

- `pageSize <= 0` or non-integer:
  - `isValid: false`
  - `error: 'INVALID_PAGE_SIZE'`
  - `totalPages: 0n`
  - `startIndex/endIndex: null`
  - `hasPrevious/hasNext: false`
- `page < 1` or non-integer:
  - `isValid: false`
  - `error: 'INVALID_PAGE_NUMBER'`
  - `totalPages` is still computed from `totalItems` and `pageSize`
  - `startIndex/endIndex: null`
  - `hasPrevious/hasNext: false`
- `page > totalPages` when dataset is non-empty:
  - `isValid: false`
  - `error: 'INVALID_PAGE_NUMBER'`
  - `startIndex/endIndex: null`
  - `hasPrevious: true` if any valid page exists
  - `hasNext: false`
- `totalItems === 0` with valid `pageSize` and `page >= 1`:
  - valid result
  - `totalPages: 0n`
  - `startIndex/endIndex: null`
  - `hasPrevious/hasNext: false`

Examples:

```ts
paginate(0n, 1, 10)
// => valid empty result

paginate(25n, 0, 10)
// => invalid: INVALID_PAGE_NUMBER

paginate(25n, 1, 0)
// => invalid: INVALID_PAGE_SIZE

paginate(10_000_000_000n, 2, 50)
// => works correctly with bigint totals
```

