/**
 * Comparison policy:
 * - Values are compared with Object.is for exact equality, so NaN matches NaN.
 * - Otherwise ordering uses the normal JavaScript < and > operators.
 * - The input array must already be sorted according to that ordering.
 * - If duplicates exist, returns the first matching index.
 * - Returns -1 when no match is found.
 */
function binarySearchFirst(arr, target) {
  let left = 0;
  let right = arr.length - 1;
  let result = -1;

  while (left <= right) {
    const mid = left + ((right - left) >> 1);
    const value = arr[mid];

    if (Object.is(value, target)) {
      result = mid;
      right = mid - 1;
      continue;
    }

    if (value < target) {
      left = mid + 1;
    } else {
      right = mid - 1;
    }
  }

  return result;
}

// Examples
console.log(binarySearchFirst([1, 2, 2, 2, 3], 2));      // 1
console.log(binarySearchFirst([NaN, NaN, 5], NaN));      // 0
console.log(binarySearchFirst([-0, 0, 0, 1], 0));        // 1 if searching 0, 0 if searching -0
console.log(binarySearchFirst(['a', 'b', 'b'], 'b'));    // 1
```

