function parseAndNormalizeIPv6(input) {
  if (typeof input !== 'string') return { valid: false, error: 'Input must be a string' };

  const value = input.trim();
  if (!value) return { valid: false, error: 'Empty input' };

  if ((value.match(/::/g) || []).length > 1) {
    return { valid: false, error: 'IPv6 address cannot contain multiple :: compressions' };
  }

  let ipv4Tail = null;
  let working = value;

  if (working.includes('.')) {
    const lastColon = working.lastIndexOf(':');
    if (lastColon === -1) {
      return { valid: false, error: 'Invalid IPv4-mapped IPv6 form' };
    }

    const ipv4Part = working.slice(lastColon + 1);
    const parsedIpv4 = parseIPv4(ipv4Part);
    if (!parsedIpv4) {
      return { valid: false, error: 'Invalid embedded IPv4 address' };
    }

    ipv4Tail = parsedIpv4;
    working = working.slice(0, lastColon) + ':ipv4';
  }

  const hasCompression = working.includes('::');
  const parts = working.split(':');
  const groups = [];

  for (let i = 0; i < parts.length; i++) {
    const part = parts[i];

    if (part === '') continue;
    if (part === 'ipv4') {
      groups.push(ipv4Tail[0], ipv4Tail[1]);
      continue;
    }
    if (!/^[0-9a-fA-F]{1,4}$/.test(part)) {
      return { valid: false, error: `Invalid IPv6 group: ${part}` };
    }
    groups.push(parseInt(part, 16));
  }

  const targetGroups = ipv4Tail ? 8 : 8;
  if (hasCompression) {
    const missing = targetGroups - groups.length;
    if (missing < 1) {
      return { valid: false, error: 'Invalid :: compression usage' };
    }

    const [left, right] = working.split('::');
    const leftGroups = expandSide(left, ipv4Tail);
    const rightGroups = expandSide(right, ipv4Tail);
    if (!leftGroups || !rightGroups) {
      return { valid: false, error: 'Invalid IPv6 address' };
    }

    const zeros = new Array(8 - leftGroups.length - rightGroups.length).fill(0);
    if (zeros.length < 1) {
      return { valid: false, error: 'Invalid :: compression usage' };
    }

    const full = [...leftGroups, ...zeros, ...rightGroups];
    if (full.length !== 8) {
      return { valid: false, error: 'Invalid IPv6 length' };
    }

    return { valid: true, normalized: canonicalIPv6(full, !!ipv4Tail) };
  }

  if (groups.length !== 8) {
    return { valid: false, error: 'IPv6 address must contain 8 groups' };
  }

  return { valid: true, normalized: canonicalIPv6(groups, !!ipv4Tail) };
}

function expandSide(side, ipv4Tail) {
  if (!side) return [];
  const parts = side.split(':');
  const out = [];

  for (const part of parts) {
    if (!part) return null;
    if (part === 'ipv4') {
      if (!ipv4Tail) return null;
      out.push(ipv4Tail[0], ipv4Tail[1]);
      continue;
    }
    if (!/^[0-9a-fA-F]{1,4}$/.test(part)) return null;
    out.push(parseInt(part, 16));
  }

  return out;
}

function parseIPv4(input) {
  const octets = input.split('.');
  if (octets.length !== 4) return null;

  const nums = [];
  for (const octet of octets) {
    if (!/^\d{1,3}$/.test(octet)) return null;
    if (octet.length > 1 && octet[0] === '0') return null;
    const n = Number(octet);
    if (n < 0 || n > 255) return null;
    nums.push(n);
  }

  return [(nums[0] << 8) | nums[1], (nums[2] << 8) | nums[3]];
}

function canonicalIPv6(groups, hadEmbeddedIPv4) {
  if (hadEmbeddedIPv4 && isIPv4Mapped(groups)) {
    return `::ffff:${groups[6] >> 8}.${groups[6] & 255}.${groups[7] >> 8}.${groups[7] & 255}`;
  }

  const hex = groups.map(n => n.toString(16));

  let bestStart = -1;
  let bestLen = 0;
  for (let i = 0; i < hex.length; ) {
    if (groups[i] !== 0) {
      i++;
      continue;
    }
    let j = i;
    while (j < groups.length && groups[j] === 0) j++;
    const len = j - i;
    if (len > bestLen && len >= 2) {
      bestStart = i;
      bestLen = len;
    }
    i = j;
  }

  if (bestStart === -1) return hex.join(':');

  const left = hex.slice(0, bestStart).join(':');
  const right = hex.slice(bestStart + bestLen).join(':');

  if (!left && !right) return '::';
  if (!left) return `::${right}`;
  if (!right) return `${left}::`;
  return `${left}::${right}`;
}

function isIPv4Mapped(groups) {
  return (
    groups[0] === 0 &&
    groups[1] === 0 &&
    groups[2] === 0 &&
    groups[3] === 0 &&
    groups[4] === 0 &&
    groups[5] === 0xffff
  );
}

// Example usage
const samples = [
  '2001:0DB8:0000:0000:0000:FF00:0042:8329',
  '2001:db8::ff00:42:8329',
  '::1',
  '::FFFF:192.168.1.1',
  '2001::db8::1'
];

for (const s of samples) {
  console.log(s, '=>', parseAndNormalizeIPv6(s));
}
```

This accepts compressed IPv6, uppercase hex, and embedded IPv4 tails, rejects multiple `::`, and normalizes valid addresses to lowercase canonical form with longest-zero-run compression.

