class Node {
  constructor(key, value) {
    this.key = key;
    this.value = value;
    this.prev = null;
    this.next = null;
  }
}

class LRUCache {
  constructor(capacity) {
    this.capacity = Math.max(0, capacity);
    this.map = new Map();
    this.head = new Node(null, null);
    this.tail = new Node(null, null);
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  get(key) {
    if (!this.map.has(key)) return -1;
    const node = this.map.get(key);
    this.#moveToFront(node);
    return node.value;
  }

  put(key, value) {
    if (this.capacity === 0) return;

    if (this.map.has(key)) {
      const node = this.map.get(key);
      node.value = value;
      this.#moveToFront(node);
      return;
    }

    const node = new Node(key, value);
    this.map.set(key, node);
    this.#insertAfterHead(node);

    if (this.map.size > this.capacity) {
      const lru = this.tail.prev;
      this.#removeNode(lru);
      this.map.delete(lru.key);
    }
  }

  #moveToFront(node) {
    this.#removeNode(node);
    this.#insertAfterHead(node);
  }

  #insertAfterHead(node) {
    node.prev = this.head;
    node.next = this.head.next;
    this.head.next.prev = node;
    this.head.next = node;
  }

  #removeNode(node) {
    node.prev.next = node.next;
    node.next.prev = node.prev;
    node.prev = null;
    node.next = null;
  }
}

// Minimal verification
function assertEqual(actual, expected, label) {
  if (!Object.is(actual, expected)) {
    throw new Error(`${label}: expected ${String(expected)}, got ${String(actual)}`);
  }
}

// capacity 0
{
  const cache = new LRUCache(0);
  cache.put('a', 1);
  assertEqual(cache.get('a'), -1, 'capacity 0 never stores entries');
}

// capacity 1
{
  const cache = new LRUCache(1);
  cache.put('a', 1);
  assertEqual(cache.get('a'), 1, 'capacity 1 stores first value');
  cache.put('b', 2);
  assertEqual(cache.get('a'), -1, 'capacity 1 evicts old key');
  assertEqual(cache.get('b'), 2, 'capacity 1 keeps newest key');
}

// repeated inserts of same key
{
  const cache = new LRUCache(2);
  cache.put('x', 1);
  cache.put('x', 2);
  cache.put('x', 3);
  assertEqual(cache.get('x'), 3, 'same key updates value');
  cache.put('y', 9);
  cache.put('z', 10);
  assertEqual(cache.get('x'), -1, 'updated key still participates in LRU order');
}

// falsy values: 0 and empty string
{
  const cache = new LRUCache(2);
  cache.put('zero', 0);
  cache.put('empty', '');
  assertEqual(cache.get('zero'), 0, 'stores 0 correctly');
  assertEqual(cache.get('empty'), '', 'stores empty string correctly');
}

console.log('All tests passed');
```

The implementation handles both edge capacities and correctly preserves falsy stored values like `0` and `''` because presence is checked with `Map.has(...)`, not truthiness.

