function topoSortWithCycle(graph) {
  const state = new Map(); // 0 = unvisited, 1 = visiting, 2 = visited
  const order = [];
  const stack = [];
  const stackIndex = new Map();

  const nodes = new Set();
  for (const [node, deps] of Object.entries(graph)) {
    nodes.add(node);
    for (const dep of deps) nodes.add(dep);
  }

  function dfs(node) {
    state.set(node, 1);
    stackIndex.set(node, stack.length);
    stack.push(node);

    for (const dep of graph[node] || []) {
      const depState = state.get(dep) || 0;

      if (depState === 0) {
        const cycle = dfs(dep);
        if (cycle) return cycle;
      } else if (depState === 1) {
        const start = stackIndex.get(dep);
        return [...stack.slice(start), dep];
      }
    }

    stack.pop();
    stackIndex.delete(node);
    state.set(node, 2);
    order.push(node);
    return null;
  }

  for (const node of nodes) {
    if ((state.get(node) || 0) === 0) {
      const cycle = dfs(node);
      if (cycle) {
        return { ok: false, cycle };
      }
    }
  }

  return { ok: true, order };
}
```

