function isValidEmailLike(input) {
  if (input === '') return false;
  if (typeof input !== 'string') return false;

  const at = input.indexOf('@');
  if (at <= 0 || at !== input.lastIndexOf('@') || at === input.length - 1) {
    return false;
  }

  const local = input.slice(0, at);
  const domain = input.slice(at + 1);

  if (local.startsWith('.') || local.endsWith('.')) return false;
  if (domain.startsWith('.') || domain.endsWith('.')) return false;
  if (domain.includes('..')) return false;

  const controlCharRegex = /[\u0000-\u001F\u007F]/u;
  if (controlCharRegex.test(local) || controlCharRegex.test(domain)) {
    return false;
  }

  return true;
}
```

This accepts Unicode in the local part, rejects empty input, control characters, leading/trailing dots, multiple `@`, and domains with empty labels (`..`, leading `.`, trailing `.`).

