function evaluateExpression(input) {
  let i = 0;
  const n = input.length;
  const values = [];
  const ops = [];
  let expectValue = true;

  const precedence = (op) => (op === '+' || op === '-') ? 1 : 2;

  const applyTop = () => {
    if (ops.length === 0) throw new Error('Malformed expression');
    const op = ops.pop();
    if (op === '(') throw new Error('Malformed expression');
    if (values.length < 2) throw new Error('Malformed expression');
    const b = values.pop();
    const a = values.pop();
    switch (op) {
      case '+': values.push(a + b); break;
      case '-': values.push(a - b); break;
      case '*': values.push(a * b); break;
      case '/':
        if (b === 0) throw new Error('Division by zero');
        values.push(a / b);
        break;
      default:
        throw new Error('Malformed expression');
    }
  };

  while (i < n) {
    const ch = input[i];

    if (ch === ' ' || ch === '\t' || ch === '\n' || ch === '\r') {
      i++;
      continue;
    }

    if (ch >= '0' && ch <= '9') {
      if (!expectValue) throw new Error('Malformed expression');
      let num = 0;
      while (i < n && input[i] >= '0' && input[i] <= '9') {
        num = num * 10 + (input[i].charCodeAt(0) - 48);
        i++;
      }
      values.push(num);
      expectValue = false;
      continue;
    }

    if (ch === '(') {
      if (!expectValue) throw new Error('Malformed expression');
      ops.push(ch);
      i++;
      continue;
    }

    if (ch === ')') {
      if (expectValue) throw new Error('Malformed expression');
      while (ops.length > 0 && ops[ops.length - 1] !== '(') {
        applyTop();
      }
      if (ops.length === 0) throw new Error('Malformed expression');
      ops.pop();
      i++;
      expectValue = false;
      continue;
    }

    if (ch === '+' || ch === '-' || ch === '*' || ch === '/') {
      if (expectValue) throw new Error('Malformed expression');
      while (
        ops.length > 0 &&
        ops[ops.length - 1] !== '(' &&
        precedence(ops[ops.length - 1]) >= precedence(ch)
      ) {
        applyTop();
      }
      ops.push(ch);
      i++;
      expectValue = true;
      continue;
    }

    throw new Error(`Invalid character: ${ch}`);
  }

  if (expectValue) throw new Error('Malformed expression');

  while (ops.length > 0) {
    if (ops[ops.length - 1] === '(') throw new Error('Malformed expression');
    applyTop();
  }

  if (values.length !== 1) throw new Error('Malformed expression');
  return values[0];
}
```

This uses iterative stacks, so nesting depth 50,000 is fine because it avoids recursion entirely.

Rejected malformed cases include:
- `()`
- `(1+)`
- `1++2`
- `1*/2`
- `( )`
- `1(2+3)`
- `2 3`
- unmatched parentheses

