```js
function diffJsonLike(a, b) {
  const changes = [];
  const seen = new WeakMap();

  walk(a, b, []);
  return changes;

  function walk(left, right, path) {
    if (Object.is(left, right)) return;

    const leftIsObj = isObjectLike(left);
    const rightIsObj = isObjectLike(right);

    if (leftIsObj || rightIsObj) {
      const circular = detectCircularPair(left, right, path);
      if (circular) {
        changes.push(circular);
        return;
      }
    }

    const leftTag = tagOf(left);
    const rightTag = tagOf(right);

    if (leftTag !== rightTag) {
      changes.push({
        path: formatPath(path),
        type: 'type-change',
        beforeType: leftTag,
        afterType: rightTag,
        before: left,
        after: right,
      });
      return;
    }

    if (!leftIsObj && !rightIsObj) {
      changes.push({
        path: formatPath(path),
        type: 'change',
        before: left,
        after: right,
      });
      return;
    }

    if (Array.isArray(left) && Array.isArray(right)) {
      diffArray(left, right, path);
      return;
    }

    diffObject(left, right, path);
  }

  function diffObject(left, right, path) {
    const keys = new Set([...Object.keys(left), ...Object.keys(right)]);

    for (const key of keys) {
      const hasLeft = Object.prototype.hasOwnProperty.call(left, key);
      const hasRight = Object.prototype.hasOwnProperty.call(right, key);
      const nextPath = path.concat(key);

      if (!hasLeft) {
        changes.push({
          path: formatPath(nextPath),
          type: 'add',
          after: right[key],
        });
        continue;
      }

      if (!hasRight) {
        changes.push({
          path: formatPath(nextPath),
          type: 'delete',
          before: left[key],
        });
        continue;
      }

      walk(left[key], right[key], nextPath);
    }
  }

  function diffArray(left, right, path) {
    const max = Math.max(left.length, right.length);

    for (let i = 0; i < max; i++) {
      const hasLeft = i in left;
      const hasRight = i in right;
      const nextPath = path.concat(i);

      if (!hasLeft && !hasRight) continue;

      if (!hasLeft) {
        changes.push({
          path: formatPath(nextPath),
          type: 'add',
          after: right[i],
        });
        continue;
      }

      if (!hasRight) {
        changes.push({
          path: formatPath(nextPath),
          type: 'delete',
          before: left[i],
        });
        continue;
      }

      walk(left[i], right[i], nextPath);
    }

    if (left.length !== right.length) {
      changes.push({
        path: formatPath(path.concat('length')),
        type: 'change',
        before: left.length,
        after: right.length,
      });
    }
  }

  function detectCircularPair(left, right, path) {
    if (!isObjectLike(left) || !isObjectLike(right)) return null;

    let inner = seen.get(left);
    if (!inner) {
      inner = new WeakMap();
      seen.set(left, inner);
    }

    const previousPath = inner.get(right);
    if (previousPath) {
      return {
        path: formatPath(path),
        type: 'circular',
        note: `Encountered previously compared pair at ${formatPath(previousPath)}`,
      };
    }

    inner.set(right, path.slice());
    return null;
  }

  function isObjectLike(value) {
    return value !== null && typeof value === 'object';
  }

  function tagOf(value) {
    if (value === null) return 'null';
    if (Array.isArray(value)) return 'array';
    return typeof value;
  }

  function formatPath(path) {
    if (path.length === 0) return '$';

    let out = '$';
    for (const part of path) {
      if (typeof part === 'number') {
        out += `[${part}]`;
      } else if (/^(?:0|[1-9]\d*|[A-Za-z_$][A-Za-z0-9_$]*)$/.test(part)) {
        out += `.${part}`;
      } else {
        out += `[${JSON.stringify(part)}]`;
      }
    }
    return out;
  }
}
```

Example output shape:

```js
[
  { path: '$.user.name', type: 'change', before: 'Ann', after: 'Ana' },
  { path: '$.items[2]', type: 'add', after: 42 },
  { path: '$.meta', type: 'type-change', beforeType: 'object', afterType: 'null', before: { ok: true }, after: null },
  { path: '$.list[4]', type: 'delete', before: 'x' },
  { path: '$.self', type: 'circular', note: 'Encountered previously compared pair at $' }
]
```

Notes:
- Additions/deletions are detected for object keys and sparse array holes via `hasOwnProperty` / `i in array`.
- Type changes are reported before descending.
- Circular references are handled safely by tracking previously compared object pairs.
- Paths use a JSONPath-like format rooted at `$`.

