def download_file(url: str, destination: str) -> bool:
    for _ in range(3):
        try:
            response = requests.get(url, stream=True, timeout=30)
        except requests.RequestException:
            return False

        if response.status_code >= 500:
            continue
        if response.status_code >= 400:
