```go
package service

import (
	"encoding/json"
	"fmt"
)

type Payload struct {
	UserID string   `json:"user_id"`
	Items  []Item   `json:"items"`
	Flags  []string `json:"flags"`
}

type Item struct {
	SKU string `json:"sku"`
	Qty int    `json:"qty"`
}

// Before: each helper reparses the same raw JSON.
func HandleBefore(body []byte) error {
	if err := validateUser(body); err != nil {
		return err
	}
	if err := processItems(body); err != nil {
		return err
	}
	if err := applyFlags(body); err != nil {
		return err
	}
	return nil
}

func validateUser(body []byte) error {
	var p Payload
	if err := json.Unmarshal(body, &p); err != nil {
		return err
	}
	if p.UserID == "" {
		return fmt.Errorf("missing user_id")
	}
	return nil
}

func processItems(body []byte) error {
	var p Payload
	if err := json.Unmarshal(body, &p); err != nil {
		return err
	}
	for _, item := range p.Items {
		_ = item
	}
	return nil
}

func applyFlags(body []byte) error {
	var p Payload
	if err := json.Unmarshal(body, &p); err != nil {
		return err
	}
	for _, flag := range p.Flags {
		_ = flag
	}
	return nil
}

// After: unmarshal once, pass structured data through helpers.
func Handle(body []byte) error {
	var p Payload
	if err := json.Unmarshal(body, &p); err != nil {
		return err
	}

	if err := validateUserParsed(&p); err != nil {
		return err
	}
	if err := processItemsParsed(&p); err != nil {
		return err
	}
	if err := applyFlagsParsed(&p); err != nil {
		return err
	}
	return nil
}

func validateUserParsed(p *Payload) error {
	if p.UserID == "" {
		return fmt.Errorf("missing user_id")
	}
	return nil
}

func processItemsParsed(p *Payload) error {
	for _, item := range p.Items {
		_ = item
	}
	return nil
}

func applyFlagsParsed(p *Payload) error {
	for _, flag := range p.Flags {
		_ = flag
	}
	return nil
}
```

**Bottleneck**
- The repeated `json.Unmarshal(body, &p)` calls are the bottleneck.
- JSON unmarshalling is CPU- and allocation-heavy, so doing it in every helper multiplies request cost.

**Big-O**
Let:
- `n` = size of the JSON payload
- `k` = number of helper functions that re-unmarshal

Before:
- Time: `O(k*n)` for parsing alone, plus helper business logic
- Space: `O(n)` per unmarshal; total transient allocation pressure scales with `k`

After:
- Time: `O(n)` for parsing once, plus helper business logic
- Space: `O(n)` for one parsed representation

If each helper also iterates over parts of the parsed payload, that traversal cost remains, but the redundant parse factor is removed.

**Refactor rule**
- Parse at the request boundary.
- Pass `*Payload` (or a request-scoped context struct) into helpers.
- Keep helpers focused on business logic, not deserialization.

